// ── Helpers ─────────────────────────────────────────────────────────

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function severityBadge(s) {
  const cls = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low', 'N/A': 'badge-draft' };
  return '<span class="badge ' + (cls[s] || 'badge-draft') + '">' + esc(s) + '</span>';
}

function statusBadge(s) {
  const cls = { Complete: 'badge-complete', 'In Progress': 'badge-progress', Draft: 'badge-draft', Scheduled: 'badge-scheduled' };
  return '<span class="badge ' + (cls[s] || 'badge-draft') + '">' + esc(s) + '</span>';
}

const avatarColors = {
