function initials(name) {
  return name.split(' ').map(n => n[0]).join('').toUpperCase();
}

function statusBadge(s) {
  const cls = { Complete: 'badge-complete', Scheduled: 'badge-scheduled', Cancelled: 'badge-cancelled' };
  return `<span class="badge ${cls[s] || 'badge-scheduled'}">${esc(s)}</span>`;
}

function speciesBadge(s) {
  const cls = { Dog: 'badge-dog', Cat: 'badge-cat' };
  return `<span class="badge ${cls[s] || 'badge-owner'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  return r === 'admin'
    ? '<span class="badge badge-admin">Admin</span>'
    : '<span class="badge badge-owner">Owner</span>';
}

