function queryAll(sql, params) {
  const results = [];
  const stmt = db.prepare(sql);
  if (params) stmt.bind(params);
  while (stmt.step()) {
    const cols = stmt.getColumnNames();
    const vals = stmt.get();
    const row = {};
    cols.forEach((c, i) => row[c] = vals[i]);
    results.push(row);
  }
  stmt.free();
  return results;
}

function queryOne(sql, params) {
  const rows = queryAll(sql, params);
  return rows.length > 0 ? rows[0] : null;
}

function runUnsafeQuery(sql) {
  const results = [];
  try {
    const stmtArr = db.exec(sql);
    if (stmtArr.length > 0) {
      const cols = stmtArr[0].columns;
      for (const row of stmtArr[0].values) {
        const obj = {};
        cols.forEach((c, i) => obj[c] = row[i]);
        results.push(obj);
      }
    }
  } catch (e) {
    // query error silently ignored
  }
  return results;
}

