app.post('/register', (req, res) => {
  const { username, password, full_name, phone } = req.body;
  if (!username || !password || !full_name) {
    return res.redirect('/?error=All+fields+are+required');
  }

  const existing = queryOne(`SELECT id FROM users WHERE username = ?`, [username]);
  if (existing) {
    return res.redirect('/?error=Username+already+taken');
  }

  const stmt = db.prepare(`INSERT INTO users (username, password, full_name, role, phone, registered_date) VALUES (?, ?, ?, 'owner', ?, ?)`);
  stmt.run([username, password, full_name, phone || '', new Date().toISOString().split('T')[0]]);
  stmt.free();

  res.redirect('/?registered=1');
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = queryOne(`SELECT * FROM users WHERE username = ? AND password = ?`, [username, password]);
  if (!user) {
    return res.redirect('/?error=Invalid+credentials');
  }
  const token = createSession(user.id, user.username);
  res.cookie('pv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

