function createSession(userId, username) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = { userId, username };
  return token;
}

function getSession(req) {
  const token = req.cookies?.nb_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const session = getSession(req);
  if (!session) return res.redirect('/');
  const rows = db.exec(`SELECT * FROM users WHERE id = ${session.userId}`);
  if (!rows.length || !rows[0].values.length) return res.redirect('/');
  const cols = rows[0].columns;
  const vals = rows[0].values[0];
  const user = {};
  cols.forEach((c, i) => user[c] = vals[i]);
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

