app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.redirect('/?error=All+fields+required');

  const rows = db.exec(`SELECT * FROM users WHERE username = '${username.replace(/'/g, "''")}' AND password = '${password.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length) {
    return res.redirect('/?error=Invalid+credentials');
  }
  const cols = rows[0].columns;
  const vals = rows[0].values[0];
  const user = {};
  cols.forEach((c, i) => user[c] = vals[i]);

  const token = createSession(user.id, user.username);
  res.cookie('nb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nb_session;
  if (token) delete sessions[token];
  res.clearCookie('nb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const acct = user.account_number;

  const inRows = db.exec(`SELECT COALESCE(SUM(amount),0) as total FROM transactions WHERE to_account = '${acct}' AND status = 'completed'`);
  const outRows = db.exec(`SELECT COALESCE(SUM(amount),0) as total FROM transactions WHERE from_account = '${acct}' AND status = 'completed'`);
  const totalIn = inRows.length ? inRows[0].values[0][0] : 0;
  const totalOut = outRows.length ? outRows[0].values[0][0] : 0;

  const benRows = db.exec(`SELECT COUNT(*) as cnt FROM beneficiaries WHERE owner_username = '${user.username}'`);
  const benCount = benRows.length ? benRows[0].values[0][0] : 0;

  const recentTx = db.exec(`SELECT * FROM transactions WHERE from_account = '${acct}' OR to_account = '${acct}' ORDER BY date DESC LIMIT 5`);
  let txHtml = '';
  if (recentTx.length && recentTx[0].values.length) {
    const cols = recentTx[0].columns;
    txHtml = recentTx[0].values.map(row => {
      const tx = {};
      cols.forEach((c, i) => tx[c] = row[i]);
      const isIncoming = tx.to_account === acct;
      return `<tr>
        <td>${esc(tx.date)}</td>
        <td>${esc(tx.description)}</td>
        <td><span class="acct-num">${esc(isIncoming ? tx.from_account : tx.to_account)}</span></td>
        <td><span class="${isIncoming ? 'amount-positive' : 'amount-negative'}">${isIncoming ? '+' : '-'}${formatCurrency(tx.amount)}</span></td>
        <td><span class="badge badge-completed">${esc(tx.status)}</span></td>
      </tr>`;
    }).join('');
  }

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome, ${esc(user.full_name.split(' ')[0])}</h1>
      <p class="subtitle">Account Overview — ${esc(user.account_number)}</p>
