app.post('/transfers', requireAuth, (req, res) => {
  const user = req.user;
  const { to_account, amount, description } = req.body;
  const amt = parseFloat(amount);

  if (!to_account || !amt || amt <= 0 || !description) {
    return res.redirect('/transfers?err=All+fields+are+required');
  }
  if (amt > user.balance) {
    return res.redirect('/transfers?err=Insufficient+funds');
  }

  const today = new Date().toISOString().split('T')[0];
  db.run(`INSERT INTO transactions (from_account, to_account, amount, description, date, status) VALUES (?, ?, ?, ?, ?, 'completed')`,
    [user.account_number, to_account, amt, description, today]);
  db.run(`UPDATE users SET balance = balance - ? WHERE id = ?`, [amt, user.id]);

  const recipientRows = db.exec(`SELECT id FROM users WHERE account_number = '${to_account.replace(/'/g, "''")}'`);
  if (recipientRows.length && recipientRows[0].values.length) {
    const recipId = recipientRows[0].values[0][0];
    db.run(`UPDATE users SET balance = balance + ? WHERE id = ?`, [amt, recipId]);
  }

  res.redirect('/transfers?msg=Transfer+of+' + formatCurrency(amt) + '+completed+successfully');
});

