function base64urlEncode(data) {
  return Buffer.from(data).toString('base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

function base64urlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  while (str.length % 4) str += '=';
  return Buffer.from(str, 'base64').toString('utf8');
}

function signJWT(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const headerB64 = base64urlEncode(JSON.stringify(header));
  const payloadB64 = base64urlEncode(JSON.stringify(payload));
  const signature = crypto.createHmac('sha256', JWT_SECRET)
    .update(headerB64 + '.' + payloadB64).digest('base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
  return headerB64 + '.' + payloadB64 + '.' + signature;
}

function verifyJWT(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const [headerB64, payloadB64, signature] = parts;
    const expected = crypto.createHmac('sha256', JWT_SECRET)
      .update(headerB64 + '.' + payloadB64).digest('base64')
      .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
    if (signature !== expected) return null;
    return JSON.parse(base64urlDecode(payloadB64));
  } catch {
    return null;
  }
}

function requireAuth(req, res, next) {
  const token = req.cookies?.nxb_token;
  if (!token) return res.redirect('/');
  const payload = verifyJWT(token);
  if (!payload) {
    res.clearCookie('nxb_token');
    return res.redirect('/');
  }
  req.userPayload = payload;
  const results = db.exec(`SELECT * FROM users WHERE id = ${payload.sub}`);
  if (!results.length || !results[0].values.length) {
    res.clearCookie('nxb_token');
    return res.redirect('/');
  }
  const cols = results[0].columns;
  const row = results[0].values[0];
  req.dbUser = {};
  cols.forEach((c, i) => { req.dbUser[c] = row[i]; });
  next();
}

function requireAuditor(req, res, next) {
  if (req.userPayload.role !== 'auditor' && req.userPayload.role !== 'admin') {
    return res.status(403).send(pageShell('Access Denied', 'auditor', req.dbUser, req.userPayload, `
      <div class="page-header">
