app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.redirect('/?error=All+fields+are+required');

  const results = db.exec(`SELECT * FROM users WHERE username = '${username.replace(/'/g, "''")}' AND password = '${password.replace(/'/g, "''")}'`);

  if (!results.length || !results[0].values.length) {
    return res.redirect('/?error=Invalid+credentials');
  }

  const cols = results[0].columns;
  const row = results[0].values[0];
  const user = {};
  cols.forEach((c, i) => { user[c] = row[i]; });

  const payload = {
    sub: user.id,
    username: user.username,
    name: user.name,
    role: user.role,
    iat: Math.floor(Date.now() / 1000)
  };

  const token = signJWT(payload);
  res.cookie('nxb_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('nxb_token');
  res.redirect('/');
});

