app.post('/transfers', requireAuth, (req, res) => {
  const user = req.dbUser;
  const { to_account, amount, description } = req.body;
  const amt = parseFloat(amount);

  if (!to_account || !amt || amt <= 0) return res.redirect('/transfers?err=Invalid+transfer+details');
  if (amt > user.balance) return res.redirect('/transfers?err=Insufficient+funds');

  db.run(`UPDATE users SET balance = balance - ${amt} WHERE id = ${user.id}`);
  const recipResult = db.exec(`SELECT id FROM users WHERE account_number = '${to_account.replace(/'/g, "''")}'`);
  if (recipResult.length && recipResult[0].values.length) {
    db.run(`UPDATE users SET balance = balance + ${amt} WHERE account_number = '${to_account.replace(/'/g, "''")}'`);
  }

  const today = new Date().toISOString().split('T')[0];
  db.run(`INSERT INTO transactions (from_account, to_account, amount, description, date, status) VALUES ('${user.account_number}', '${to_account.replace(/'/g, "''")}', ${amt}, '${(description || 'Transfer').replace(/'/g, "''")}', '${today}', 'completed')`);

  res.redirect('/transfers?msg=Transfer+of+$' + amt.toFixed(2) + '+completed+successfully');
});

