app.get('/session', requireAuth, (req, res) => {
  const user = req.dbUser;
  const payload = req.userPayload;
  const token = req.cookies?.nxb_token || '';

  const parts = token.split('.');
  let headerDisplay = '';
  let payloadDisplay = '';
  try {
    headerDisplay = JSON.stringify(JSON.parse(base64urlDecode(parts[0])), null, 2);
    payloadDisplay = JSON.stringify(JSON.parse(base64urlDecode(parts[1])), null, 2);
  } catch (e) {
    headerDisplay = 'Error decoding';
    payloadDisplay = 'Error decoding';
