app.post('/admin/verify', requireAuth, (req, res) => {
  const { admin_password } = req.body;
  if (admin_password !== ADMIN_PASSWORD) {
    return res.redirect('/admin?error=Invalid+admin+password.+Access+denied.');
  }
  const payload = req.userPayload;
  const newPayload = { ...payload, role: 'admin', admin_verified: true };
  const token = signJWT(newPayload);
  res.cookie('nxb_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/admin/dashboard');
});

