  `));
});

app.post('/api/fetch-url', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) {
    return res.json({ error: 'No URL provided' });
  }

  try {
    const parsedUrl = new URL(url);
    const allowedProtocols = ['http:', 'https:'];
    if (!allowedProtocols.includes(parsedUrl.protocol)) {
      return res.json({ error: 'Only HTTP and HTTPS protocols are supported' });
    }

    const hostname = parsedUrl.hostname;
    if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '0.0.0.0') {
      const targetPath = parsedUrl.pathname + parsedUrl.search;

      const internalApp = express();
      const fakeReq = {
        method: 'GET',
        url: targetPath,
        path: parsedUrl.pathname,
        query: Object.fromEntries(parsedUrl.searchParams),
        headers: {
          'host': hostname,
          'x-forwarded-for': '127.0.0.1',
        },
      };

      if (parsedUrl.pathname === '/internal/employee-search') {
        const referer = fakeReq.headers['referer'];
        if (referer) {
          return res.json({ body: JSON.stringify({ error: 'Access denied. This endpoint is for internal server-to-server communication only.' }) });
        }

        const q = parsedUrl.searchParams.get('q') || '';
        if (!q) {
          return res.json({ body: JSON.stringify({ error: 'Missing required parameter: q' }) });
        }

        try {
          const query = `SELECT id, first_name, last_name, email, department, title FROM employees WHERE first_name LIKE '%${q}%' OR last_name LIKE '%${q}%' OR email LIKE '%${q}%'`;
          const results = db.exec(query);
          let employees = [];
          if (results.length > 0) {
            const cols = results[0].columns;
            employees = results[0].values.map(row => {
              const obj = {};
              cols.forEach((c, i) => obj[c] = row[i]);
              return obj;
            });
          }
          return res.json({ body: JSON.stringify({ results: employees, count: employees.length }, null, 2) });
        } catch (sqlErr) {
          return res.json({ body: JSON.stringify({ error: 'Database error: ' + sqlErr.message }) });
        }
      }

      return res.json({ body: JSON.stringify({ error: 'Internal endpoint not found: ' + parsedUrl.pathname }) });
    }

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      signal: controller.signal,
      headers: { 'User-Agent': 'HorizonCorp-LinkPreview/1.0' },
      redirect: 'follow',
    });
    clearTimeout(timeout);

    const contentType = response.headers.get('content-type') || '';
    let body;
    if (contentType.includes('text') || contentType.includes('json') || contentType.includes('xml')) {
      body = await response.text();
      if (body.length > 10000) body = body.substring(0, 10000) + '\n\n[...truncated at 10,000 characters]';
    } else {
      body = `[Binary content: ${contentType}, ${response.headers.get('content-length') || 'unknown'} bytes]`;
    }

    return res.json({ body, status: response.status, contentType });
  } catch (err) {
    if (err.name === 'AbortError') {
      return res.json({ error: 'Request timed out (5s limit)' });
    }
    return res.json({ error: err.message });
  }
});

app.get('/internal/employee-search', (req, res) => {
  const referer = req.headers['referer'];
  if (!referer) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal service-to-service requests. A valid Referer header from an authorized internal service is required.',
    });
  }

  const q = req.query.q;
  if (!q) {
    return res.status(400).json({ error: 'Missing required parameter: q' });
  }

  try {
    const query = `SELECT id, first_name, last_name, email, department, title FROM employees WHERE first_name LIKE '%${q}%' OR last_name LIKE '%${q}%' OR email LIKE '%${q}%'`;
    const results = db.exec(query);
    let employees = [];
    if (results.length > 0) {
      const cols = results[0].columns;
      employees = results[0].values.map(row => {
        const obj = {};
        cols.forEach((c, i) => obj[c] = row[i]);
        return obj;
      });
    }
    res.json({ results: employees, count: employees.length });
  } catch (sqlErr) {
    res.status(500).json({ error: 'Database error: ' + sqlErr.message });
  }
});

