function createSession(playerId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = playerId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.nexus_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const playerId = getSession(req);
  if (!playerId) return res.redirect('/');
  const player = players.find(p => p.id === playerId);
  if (!player) return res.redirect('/');
  req.player = player;
  next();
}

function requireAdmin(req, res, next) {
  const playerId = getSession(req);
  if (!playerId) return res.status(401).json({ error: 'Authentication required' });
  const player = players.find(p => p.id === playerId);
  if (!player || player.role !== 'admin') return res.status(403).json({ error: 'Admin access required' });
  req.player = player;
  next();
}

