function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function rankBadge(rank) {
  const cls = { Diamond: 'badge-diamond', Platinum: 'badge-platinum', Gold: 'badge-gold', Silver: 'badge-silver', Unranked: 'badge-common' };
  return `<span class="badge ${cls[rank] || 'badge-common'}">${esc(rank)}</span>`;
}

function rarityBadge(rarity) {
  const cls = { Mythic: 'badge-mythic', Legendary: 'badge-legendary', Epic: 'badge-epic', Rare: 'badge-rare', Uncommon: 'badge-uncommon', Common: 'badge-common' };
  return `<span class="badge ${cls[rarity] || 'badge-common'}">${esc(rarity)}</span>`;
