app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const player = players.find(p => p.username === username && p.password === password);
  if (!player) return res.redirect('/?error=Invalid+credentials');
  const token = createSession(player.id);
  res.cookie('nexus_session', token, { httpOnly: false, sameSite: 'lax' });
  if (player.role === 'admin') return res.redirect('/admin');
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nexus_session;
  if (token) delete sessions[token];
  res.clearCookie('nexus_session');
  res.redirect('/');
});

