app.get('/bot/visit', requireAuth, (req, res) => {
  const adminUser = players.find(p => p.role === 'admin');
  const botToken = createSession(adminUser.id);

  let xssTriggered = false;
  for (const msg of arenaChatMessages) {
    const lower = msg.content.toLowerCase();
    if (lower.includes('<script') || lower.includes('onerror') || lower.includes('onload') || lower.includes('onfocus') || lower.includes('onmouseover') || lower.includes('javascript:') || lower.includes('<img') || lower.includes('<svg') || lower.includes('<iframe') || lower.includes('<body') || lower.includes('fetch(') || lower.includes('xmlhttp') || lower.includes('document.cookie')) {
      xssTriggered = true;

      const cookieStr = `nexus_session=${botToken}`;
      const scriptContent = msg.content;

      const collectMatch = scriptContent.match(/\/webhook\/collect\?data=/i);
      if (collectMatch) {
        webhookData.push({
          timestamp: new Date().toISOString().replace('T', ' ').substring(0, 19),
          source: 'AdminBot/1.0 (Moderation)',
          data: cookieStr
        });
      }
      break;
    }
  }

  const player = req.player;
  const statusMsg = xssTriggered
    ? '<div class="success-msg">🤖 Admin bot visited the Arena Chat and processed all messages. Check the webhook log for any captured data.</div>'
    : '<div class="info-msg">🤖 Admin bot visited the Arena Chat. No actionable content was found to process.</div>';

  res.send(pageShell('Bot Visit', 'chat', player, `
    <div class="page-header">
      <h1>🤖 Admin Bot</h1>
      <p class="subtitle">Simulated admin moderation bot</p>
    </div>
    ${statusMsg}
    <div style="margin-top:16px;display:flex;gap:10px;">
      <a href="/arena-chat" class="btn btn-primary">← Back to Chat</a>
      <a href="/webhook" class="btn btn-neon">View Webhook Log</a>
    </div>
  `));
});

