              html += '<div style="font-size:0.8rem;color:var(--text-muted);margin-bottom:12px;">Inventory (' + data.inventory.length + ' items):</div>';
              data.inventory.forEach(function(item) {
                html += '<div class="inventory-item"><div class="item-icon">' + (item.rarity === 'Mythic' ? '🌟' : item.rarity === 'Legendary' ? '⚡' : item.rarity === 'Epic' ? '💎' : '📦') + '</div>';
                html += '<div class="item-info"><div class="item-name">' + escapeHtml(item.name) + ' <span class="badge badge-' + item.rarity.toLowerCase() + '">' + escapeHtml(item.rarity) + '</span></div>';
                html += '<div class="item-desc">' + escapeHtml(item.description) + '</div>';
                html += '<div style="font-size:0.68rem;color:var(--text-muted);margin-top:4px;font-family:var(--font-mono);">ID: ' + escapeHtml(item.itemId) + '</div></div></div>';
              });
              document.getElementById('playerDetailContent').innerHTML = html;
            }
            document.getElementById('playerDetail').style.display = 'block';
          });
      }
      function escapeHtml(str) {
        var div = document.createElement('div');
        div.textContent = str;
        return div.innerHTML;
      }
    </script>
  `));
});

app.get('/admin/api/players/:id/inventory', requireAdmin, (req, res) => {
  const playerId = parseInt(req.params.id);
  const target = players.find(p => p.id === playerId);

  if (!target) {
    return res.status(404).json({ error: 'Player not found' });
  }

  res.json({
    id: target.id,
    username: target.username,
    displayName: target.displayName,
    rank: target.rank,
    level: target.level,
    inventory: target.inventory.map(item => ({
      itemId: item.itemId,
      name: item.name,
      rarity: item.rarity,
      description: item.description,
      equipped: item.equipped
    }))
  });
});

