function base64urlEncode(obj) {
  return Buffer.from(JSON.stringify(obj))
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function base64urlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  while (str.length % 4) str += '=';
  return JSON.parse(Buffer.from(str, 'base64').toString());
}

function signJwt(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const headerB64 = base64urlEncode(header);
  const payloadB64 = base64urlEncode(payload);
  const signature = crypto.createHmac('sha256', JWT_SECRET)
    .update(headerB64 + '.' + payloadB64)
    .digest('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
  return headerB64 + '.' + payloadB64 + '.' + signature;
}

function verifyJwt(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const [headerB64, payloadB64, sig] = parts;
    const expectedSig = crypto.createHmac('sha256', JWT_SECRET)
      .update(headerB64 + '.' + payloadB64)
      .digest('base64')
      .replace(/=/g, '')
      .replace(/\+/g, '-')
      .replace(/\//g, '_');
    if (sig !== expectedSig) return null;
    return base64urlDecode(payloadB64);
  } catch {
    return null;
  }
}

function requireAuth(req, res, next) {
  const token = req.cookies?.mh_token;
  if (!token) return res.redirect('/');
  const payload = verifyJwt(token);
  if (!payload) return res.redirect('/');
  const user = users.find(u => u.id === payload.uid);
  if (!user) return res.redirect('/');
  req.user = user;
  req.tokenPayload = payload;
  req.tokenRole = payload.role;
  next();
}

function requireRole(roles) {
  return (req, res, next) => {
    if (!roles.includes(req.tokenRole)) {
      return res.status(403).send(pageShell('Access Denied', '', req.user, req.tokenRole, `
        <div class="page-header">
          <h1>⛔ Access Denied</h1>
          <p class="subtitle">Your role <code style="font-family:var(--font-mono);color:var(--accent-red);">${esc(req.tokenRole)}</code> does not have permission to access this resource.</p>
        </div>
        <a href="/dashboard" class="btn btn-primary">← Back to Dashboard</a>
      `));
    }
    next();
  };
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

