function initials(name) {
  return name.split(' ').filter(n => n.length > 0).map(n => n[0]).join('').substring(0, 2).toUpperCase();
}

function statusBadge(s) {
  const cls = { Active: 'badge-active', Observation: 'badge-observation', Discharged: 'badge-discharged', Restricted: 'badge-restricted' };
  return '<span class="badge ' + (cls[s] || 'badge-discharged') + '">' + esc(s) + '</span>';
}

function roleBadge(r) {
  const cls = { admin: 'badge-admin', researcher: 'badge-researcher', doctor: 'badge-doctor', user: 'badge-user' };
  return '<span class="badge ' + (cls[r] || 'badge-user') + '">' + esc(r) + '</span>';
}

