  const token = req.cookies?.mh_token || '';

  const parts = token.split('.');
  let headerJson = '', payloadJson = '';
  try {
    headerJson = JSON.stringify(base64urlDecode(parts[0]), null, 2);
    payloadJson = JSON.stringify(base64urlDecode(parts[1]), null, 2);
  } catch(e) {
    headerJson = 'Error decoding';
    payloadJson = 'Error decoding';
  }

  res.send(pageShell('Session Info', 'session', user, role, `
