          <input type="text" id="otp-input" placeholder="Enter OTP code" style="padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;font-family:var(--font-mono);flex:1;">
