});

app.post('/api/admin/verify', requireAuth, requireRole(['admin']), (req, res) => {
  const { otp } = req.body;
  if (!otp || otp !== ADMIN_OTP) {
    return res.status(403).json({ error: 'Invalid OTP code. A valid one-time code is required for admin operations.' });
  }
  res.json({ message: 'OTP verified successfully.' });
});

