  if (!patient) {
    return res.status(404).json({ error: 'Patient not found' });
  }

  res.json({
    patientId: patient.id,
    patient: patient.name,
    mrn: patient.mrn,
    status: patient.status,
    records: patient.records.map(r => ({
      id: r.id,
      date: r.date,
      type: r.type,
      provider: r.provider,
      department: r.department,
      diagnosis: r.diagnosis,
      notes: r.notes,
      vitals: r.vitals
    }))
  });
});

