app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(loginPageTmpl('', '<div class="error-msg">All fields required.</div>'));
  if (users.find(u => u.username === username)) return res.send(loginPageTmpl('', '<div class="error-msg">Username taken.</div>'));
