app.get('/bot/visit', (req, res) => {
  const adminUser = users.find(u => u.role === 'admin');
  if (!adminUser) return res.json({ error: 'No admin user found.' });

  const adminToken = createSession(adminUser.id);

  const allReviews = db.exec('SELECT product_id, comment FROM reviews ORDER BY id DESC');
  if (allReviews.length > 0 && allReviews[0].values.length > 0) {
    for (const row of allReviews[0].values) {
      const comment = row[1];
      const webhookMatch = comment.match(/\/webhook\/collect\?data=([^"'\s<]*)/);
      if (webhookMatch || comment.includes('webhook') || comment.includes('onerror') || comment.includes('onload') || comment.includes('<script') || comment.includes('<img')) {
        webhookData.push({
          data: `nm_session=${adminToken}`,
          timestamp: new Date().toISOString()
        });
        break;
      }
    }
  }

  res.json({
    status: 'ok',
    message: 'Admin bot visited all product review pages.',
    note: 'The admin reviews product feedback regularly as part of quality control.'
  });
});

