import express from 'express';
import cookieParser from 'cookie-parser';
import crypto from 'crypto';
import fs from 'fs';
import initSqlJs from 'sql.js';

const app = express();
app.use(express.urlencoded({ extended: true }));
app.use(express.json());
app.use(cookieParser());

const flag = fs.readFileSync('.flag', 'utf-8').trim();

let db;
const sessions = {};

function createSession(userId, role) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = { userId, role };
  return token;
}

function getSession(req) {
  const token = req.cookies?.hs_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const session = getSession(req);
  if (!session) return res.redirect('/login');
  req.session = session;
  const user = db.exec("SELECT * FROM users WHERE id = " + session.userId);
  if (!user[0] || !user[0].values[0]) return res.redirect('/login');
  const cols = user[0].columns;
  const vals = user[0].values[0];
  req.user = {};
  cols.forEach((c, i) => req.user[c] = vals[i]);
  next();
}

function esc(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

