    position: absolute; top: 0; left: 0; right: 0; bottom: 0;
    background: #374151; border-radius: 22px; transition: 0.3s;
  }
  .toggle-slider::before {
    content: ''; position: absolute; height: 16px; width: 16px;
    left: 3px; bottom: 3px; background: #fff; border-radius: 50%;
    transition: 0.3s;
  }
  .toggle-switch input:checked + .toggle-slider { background: var(--accent-green); }
  .toggle-switch input:checked + .toggle-slider::before { transform: translateX(20px); }

  textarea {
    width: 100%; padding: 12px; background: var(--bg-input);
    border: 1px solid var(--border); border-radius: var(--radius);
    color: var(--text-primary); font-size: 0.85rem; font-family: var(--font-sans);
    resize: vertical; min-height: 80px;
  }
  textarea:focus { outline: none; border-color: var(--accent); box-shadow: 0 0 0 3px rgba(59,130,246,0.1); }

  .fade-in { animation: fadeIn 0.3s ease-out; }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }

  .expandable-section { margin-top: 10px; }
  .expand-btn { cursor: pointer; color: var(--accent); font-size: 0.8rem; font-weight: 600; background: none; border: none; padding: 4px 0; }
  .expand-btn:hover { text-decoration: underline; }
`;

function initials(name) {
  return String(name || '').split(' ').map(n => n[0]).join('').toUpperCase();
}

