app.get('/jobs', requireAuth, (req, res) => {
  const user = req.user;
  const search = req.query.search || '';
  const jobType = req.query.job_type || '';
  const page = parseInt(req.query.page) || 1;

  let sql = "SELECT j.*, u.full_name as company_name FROM jobs j JOIN users u ON j.employer_id = u.id WHERE j.status = 'active'";
  const params = [];

  if (search) {
    sql += " AND (j.title LIKE ? OR j.skills LIKE ? OR j.location LIKE ?)";
    params.push('%' + search + '%', '%' + search + '%', '%' + search + '%');
  }
  if (jobType) {
    sql += " AND j.job_type = ?";
    params.push(jobType);
  }

  sql += " ORDER BY j.created_at DESC";
  const allJobs = dbAll(sql, params);

  const perPage = 5;
  const totalPages = Math.ceil(allJobs.length / perPage) || 1;
  const jobs = allJobs.slice((page - 1) * perPage, page * perPage);

  const jobCards = jobs.map(j => {
    const skills = (j.skills || '').split(',').filter(Boolean).map(s =>
      '<span class="skill-pill">' + esc(s.trim()) + '</span>').join('');
    return `
      <div class="job-card">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;">
          <div>
            <div class="job-title">${esc(j.title)}</div>
            <div class="job-meta">${esc(j.company_name)} · ${esc(j.location)} · Posted ${esc(j.created_at)}</div>
          </div>
          <span class="badge badge-${j.job_type}">${esc(j.job_type)}</span>
        </div>
        <div class="job-salary">\$${(j.salary_min/1000).toFixed(0)}k — \$${(j.salary_max/1000).toFixed(0)}k</div>
        <div class="job-skills">${skills}</div>
        <div class="job-actions">
          ${user.role === 'candidate' ? '<form method="POST" action="/api/applications" style="display:inline;"><input type="hidden" name="job_id" value="' + j.id + '"><button type="submit" class="btn btn-primary btn-sm">Apply Now</button></form>' : '<span class="btn btn-ghost btn-sm">Employer View</span>'}
        </div>
      </div>`;
  }).join('');

  let paginationHTML = '<div class="pagination">';
  for (let i = 1; i <= totalPages; i++) {
    paginationHTML += '<button class="page-btn ' + (i === page ? 'active' : '') + '" onclick="window.location.href=\'/jobs?page=' + i + '&search=' + encodeURIComponent(search) + '&job_type=' + encodeURIComponent(jobType) + '\'">' + i + '</button>';
  }
  paginationHTML += '</div>';

  res.send(pageShell('Job Listings', 'jobs', user, `
    <div class="page-header">
      <h1>Job Listings</h1>
      <p class="subtitle">Browse open positions from top companies</p>
    </div>

    <form class="search-bar" method="GET" action="/jobs">
      <input type="text" name="search" placeholder="Search by title, skill, or location..." value="${esc(search)}">
      <select name="job_type">
        <option value="">All Types</option>
        <option value="remote" ${jobType==='remote'?'selected':''}>Remote</option>
        <option value="hybrid" ${jobType==='hybrid'?'selected':''}>Hybrid</option>
        <option value="onsite" ${jobType==='onsite'?'selected':''}>Onsite</option>
      </select>
      <button type="submit" class="btn btn-primary btn-sm">Search</button>
    </form>

    ${jobCards || '<p style="color:var(--text-muted);">No jobs found matching your criteria.</p>'}
    ${paginationHTML}
  `));
});

