    [appId]
  );

  if (!application) {
    return res.send(pageShell('Not Found', 'applications', user,
      '<div class="page-header"><h1>Application Not Found</h1></div>'));
  }

  if (user.role === 'candidate' && application.user_id !== user.id) {
    return res.send(pageShell('Access Denied', 'applications', user,
      '<div class="page-header"><h1>Access Denied</h1><p class="subtitle">You can only view your own applications.</p></div>'));
  }

  const docs = dbAll("SELECT * FROM documents WHERE application_id = ?", [appId]);

  const statusSteps = ['submitted', 'under_review', 'interview', 'offer'];
  const currentIdx = statusSteps.indexOf(application.status);
  const isRejected = application.status === 'rejected';

