    let cls = '';
    if (isRejected) {
      cls = i === 0 ? 'completed' : '';
    } else if (i < currentIdx) {
      cls = 'completed';
    } else if (i === currentIdx) {
      cls = 'active';
    }
    return '<div class="timeline-step ' + cls + '">' + esc(s.replace('_', ' ')) + '</div>';
  }).join('');

  const docCards = docs.map(d => `
    <div class="doc-card">
      <div class="doc-icon">📄</div>
