  const appUser = dbGet("SELECT * FROM users WHERE id = ?", [application.user_id]);

  res.send(pageShell('Application Detail', 'applications', user, `
    <div class="page-header">
      <h1>${esc(application.job_title)}</h1>
      <p class="subtitle">${esc(application.company_name)} · ${esc(application.job_location)} · Applied ${esc(application.created_at)}</p>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:8px;">Application Status</h3>
      ${isRejected ? '<div style="text-align:center;padding:16px;"><span class="badge badge-rejected" style="font-size:0.85rem;padding:8px 16px;">REJECTED</span></div>' : '<div class="status-timeline">' + timelineHTML + '</div>'}
    </div>

    <div style="display:grid;grid-template-columns:2fr 1fr;gap:20px;">
      <div>
        <div class="card" style="margin-bottom:20px;">
          <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:12px;">Documents</h3>
          ${docCards || '<p style="color:var(--text-muted);font-size:0.85rem;">No documents attached to this application.</p>'}
        </div>

        <div class="card">
          <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:12px;">Private Notes</h3>
          <textarea readonly style="min-height:100px;">${esc(application.private_notes)}</textarea>
          ${user.role === 'employer' ? '<div style="margin-top:12px;"><h4 style="font-family:var(--font-mono);font-size:0.82rem;color:var(--accent-amber);margin-bottom:8px;">Internal Notes (Employer)</h4><textarea placeholder="Add internal notes about this candidate..." style="min-height:80px;"></textarea></div>' : ''}
