// ── Helpers ─────────────────────────────────────────────────────────

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function renderSidebar(activePage, user) {
  const channelLinks = channels.map(ch => {
    const isActive = activePage === 'channel-' + ch.id;
    return '<a href="/channels/' + ch.id + '" class="' + (isActive ? 'active' : '') + '">' +
      '<span class="ch-icon">' + esc(ch.icon) + '</span> ' + esc(ch.name) + '</a>';
  }).join('');

  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="logo">NL</div>
        <h1>Nexus<span>Link</span></h1>
      </div>
      <div class="sidebar-nav">
        <div class="sidebar-section-label">Navigation</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="ch-icon">~</span> Dashboard
        </a>
        <a href="/api/docs" class="${activePage === 'docs' ? 'active' : ''}">
          <span class="ch-icon">?</span> API Docs
        </a>
        <div class="sidebar-section-label">Channels</div>
        ${channelLinks}
        <div class="sidebar-section-label" style="margin-top:auto;"></div>
        <a href="/logout"><span class="ch-icon">x</span> Sign Out</a>
      </div>
      <div class="sidebar-user">
        <div class="avatar">${esc(user.avatar)}</div>
        <div>
          <div class="uname">${esc(user.name)}</div>
          <div class="urole">${esc(user.role)}</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — NexusLink</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">
    ${content}
  </main>
</div>
</body></html>`;
}

