  `));
});

// Channel preview form handler — renders the result in the page
app.post('/channels/:name/preview', requireAuth, async (req, res) => {
  const user = req.user;
  const ch = channels.find(c => c.id === req.params.name);
  if (!ch) return res.redirect('/dashboard');

  const url = req.body.url;
  let previewHTML = '';

  if (!url) {
    previewHTML = '<div class="preview-result"><div class="pr-status">Error: No URL provided</div></div>';
  } else {
    try {
      const fetchRes = await fetch(url, { redirect: 'follow', signal: AbortSignal.timeout(5000) });
      const body = await fetchRes.text();
      const truncated = body.length > 4000 ? body.substring(0, 4000) + '\n\n[... truncated ...]' : body;
      previewHTML = `
        <div class="preview-result">
          <div class="pr-status">Fetched ${esc(url)} — HTTP ${fetchRes.status}</div>
          ${esc(truncated)}
        </div>`;
    } catch (e) {
      previewHTML = `
        <div class="preview-result">
          <div class="pr-status">Error fetching URL</div>
          ${esc(e.message)}
        </div>`;
    }
  }

  const links = sharedLinks.filter(l => l.channel === ch.id);
  const linkCards = links.map(l => `
    <div class="link-card">
      <div class="lc-url">${esc(l.url)}</div>
      <div class="lc-title">${esc(l.title)}</div>
      <div class="lc-snippet">${esc(l.snippet)}</div>
      <div class="lc-meta">
        <span class="badge badge-${l.status}">${esc(l.status)}</span>
        <span>${esc(l.author)}</span>
        <span>${esc(l.date)}</span>
      </div>
    </div>`).join('');

  res.send(pageShell('#' + ch.name + ' — Preview', 'channel-' + ch.id, user, `
    <div class="channel-header">
      <div class="ch-hash">#</div>
      <div>
        <h2>${esc(ch.name)}</h2>
        <div class="ch-desc">${esc(ch.description)}</div>
      </div>
    </div>

    <div class="preview-form">
      <h3>Share a Link</h3>
      <p style="font-size:0.78rem;color:var(--text-muted);margin-bottom:12px;">
        Paste a URL below to generate a preview and share it with the channel.
      </p>
      <form method="POST" action="/channels/${ch.id}/preview">
        <div class="form-row">
          <input type="text" name="url" value="${esc(url)}" autocomplete="off" required>
          <button type="submit">Preview Link</button>
        </div>
