app.post('/api/preview', requireAuth, async (req, res) => {
  const url = req.body.url;
  if (!url) return res.status(400).json({ error: 'Missing url parameter' });

  try {
    const fetchRes = await fetch(url, { redirect: 'follow', signal: AbortSignal.timeout(5000) });
    const body = await fetchRes.text();
    res.json({
      url,
      status: fetchRes.status,
      contentType: fetchRes.headers.get('content-type'),
      body: body.length > 8000 ? body.substring(0, 8000) : body,
    });
  } catch (e) {
    res.status(502).json({ error: 'Failed to fetch URL', details: e.message });
  }
});

