const sessions = {};

function createSession(agentId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = agentId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.df_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const agentId = getSession(req);
  if (!agentId) return res.redirect('/');
  try {
    const rows = db.exec('SELECT * FROM agents WHERE id = ' + agentId);
    if (!rows.length || !rows[0].values.length) return res.redirect('/');
    const cols = rows[0].columns;
    const vals = rows[0].values[0];
    const agent = {};
    cols.forEach((c, i) => agent[c] = vals[i]);
    req.agent = agent;
    next();
  } catch(e) {
    return res.redirect('/');
  }
}

function dbQuery(sql) {
  return db.exec(sql);
}

function esc(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

