function agentInitials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function statusBadge(s) {
  const map = {
    'Open': 'badge-open',
    'In Progress': 'badge-progress',
    'Pending': 'badge-pending',
    'Resolved': 'badge-resolved',
  };
  return '<span class="badge ' + (map[s] || 'badge-agent') + '">' + esc(s) + '</span>';
}

function priorityBadge(p) {
  const map = { Urgent: 'badge-urgent', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  const dot = { Urgent: 'red', High: 'amber', Medium: 'blue', Low: '' };
  const d = dot[p] ? '<span class="pulse-dot ' + dot[p] + '"></span>' : '';
  return '<span class="badge ' + (map[p] || 'badge-low') + '">' + d + esc(p) + '</span>';
}

function roleBadge(r) {
  if (r === 'Administrator') return '<span class="badge badge-admin">' + esc(r) + '</span>';
  if (r === 'Senior Agent') return '<span class="badge badge-senior">' + esc(r) + '</span>';
  return '<span class="badge badge-agent">' + esc(r) + '</span>';
}

