app.post('/login', (req, res) => {
  const { username, password } = req.body;
  try {
    const rows = db.exec(
      "SELECT * FROM agents WHERE username = '" + username + "' AND password = '" + password + "'"
    );
    if (!rows.length || !rows[0].values.length) {
      return res.send(loginHtml('Invalid username or password.', '', false));
    }
    const cols = rows[0].columns;
    const vals = rows[0].values[0];
    const agent = {};
    cols.forEach((c, i) => agent[c] = vals[i]);
    const token = createSession(agent.id);
    res.cookie('df_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch(e) {
    return res.send(loginHtml('Authentication error. Please try again.', '', false));
  }
});

app.post('/register', (req, res) => {
  const { full_name, username, password } = req.body;
  if (!full_name || !username || !password) {
    return res.send(loginHtml('', 'All fields are required.', false));
  }
  try {
    db.run(
      "INSERT INTO agents (username, password, full_name, role, department, email, avatar_color) VALUES ('" +
      username + "', '" + password + "', '" + full_name + "', 'Agent', 'Tier 1 Support', '" + username + "@deskflow.io', '#64748b')"
    );
    return res.send(loginHtml('', '', true));
  } catch(e) {
    if (e.message && e.message.includes('UNIQUE')) {
      return res.send(loginHtml('', 'Username already taken.', false));
    }
    return res.send(loginHtml('', 'Registration failed. Please try again.', false));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.df_session;
  if (token) delete sessions[token];
  res.clearCookie('df_session');
  res.redirect('/');
});

