app.get('/tickets/:id', requireAuth, (req, res) => {
  const agent = req.agent;
  const ticketId = req.params.id;
  let ticket = null;
  let notesHtml = '';
  let assignedAgent = null;

  try {
    const result = db.exec(
      'SELECT t.*, a.full_name as agent_name, a.avatar_color as agent_color FROM tickets t ' +
      'LEFT JOIN agents a ON t.assigned_to = a.id WHERE t.id = ' + parseInt(ticketId)
    );
    if (!result.length || !result[0].values.length) {
      return res.send(shell('Not Found', 'tickets', agent,
        '<div class="topbar"><div class="topbar-title"><h1>Ticket Not Found</h1></div></div><p style="color:var(--text-muted);">No ticket with that ID exists.</p>'
      ));
    }
    const cols = result[0].columns;
    const vals = result[0].values[0];
    ticket = {};
    cols.forEach((c, i) => ticket[c] = vals[i]);
  } catch(e) {
    return res.send(shell('Error', 'tickets', agent,
      '<div class="topbar"><div class="topbar-title"><h1>Error</h1></div></div><p style="color:var(--red);">' + esc(e.message) + '</p>'
