function starsHtml(rating) {
  const full = Math.floor(rating);
  const half = rating % 1 >= 0.5 ? 1 : 0;
  return '★'.repeat(full) + (half ? '½' : '') + ' ' + rating.toFixed(1);
}

function bookSpineColor(genre) {
  const map = {
    'Fiction': 'linear-gradient(135deg,#7aadcf,#5889a8)',
    'Science Fiction': 'linear-gradient(135deg,#6abf7b,#4a9f5b)',
    'History': 'linear-gradient(135deg,#c4a464,#8a6a30)',
    'Fantasy': 'linear-gradient(135deg,#b07fd4,#8a5fb0)',
    'Biography': 'linear-gradient(135deg,#e06b6b,#b04a4a)',
    'Academic': 'linear-gradient(135deg,#94a3b8,#64748b)',
    'Science': 'linear-gradient(135deg,#7aadcf,#4a8aaf)',
    'Thriller': 'linear-gradient(135deg,#e06b6b,#c4a464)',
    'Mystery': 'linear-gradient(135deg,#b07fd4,#7aadcf)',
  };
  return map[genre] || 'linear-gradient(135deg,#c4a464,#8a6a30)';
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('').toUpperCase();
}

