    return res.send(loginHtml.replace('##LOGIN_ERROR##',
      '<div class="error-msg">Invalid username or password. Please try again.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('arc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.cookie('arc_flag', flag, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.arc_session;
  if (token) delete sessions[token];
  res.clearCookie('arc_session');
  res.clearCookie('arc_flag');
  res.redirect('/');
});

