app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const sessionToken = createSession(user.id);
  res.cookie('session', sessionToken, { httpOnly: true, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.session;
  if (token) delete sessions[token];
  res.clearCookie('session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const userLoans = loanHistory[user.id] || [];
  const userRes = reservations[user.id] || [];
  const activeLoans = userLoans.filter(l => !l.returned);
  const readyPickup = userRes.filter(r => r.status === 'Ready for Pickup');

  res.send(renderLayout(user, 'dashboard', 'Dashboard', `
    <div class="page-header">
      <h2>Welcome back, ${user.name.split(' ')[0]}!</h2>
      <p>Here's your library activity overview</p>
    </div>

    <div class="stats-grid">
      <div class="stat-card">
        <div class="stat-icon">📚</div>
        <div class="stat-label">Books Checked Out</div>
        <div class="stat-value">${activeLoans.length}</div>
      </div>
      <div class="stat-card">
        <div class="stat-icon">📊</div>
        <div class="stat-label">Total Loans</div>
        <div class="stat-value">${user.totalLoans}</div>
      </div>
      <div class="stat-card">
        <div class="stat-icon">🔖</div>
        <div class="stat-label">Active Reservations</div>
        <div class="stat-value">${userRes.length}</div>
      </div>
      <div class="stat-card">
        <div class="stat-icon">💰</div>
