      </div>
    </div>

    <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 24px;">
      <div class="card">
        <div class="card-header">
          <h3>📖 Currently Checked Out</h3>
        </div>
        <div class="card-body" style="padding: 0;">
          ${activeLoans.length > 0 ? `
            <table>
              <thead>
                <tr>
