                  </tr>
                `).join('')}
              </tbody>
            </table>
          ` : '<div class="empty-state"><span class="icon">✅</span><p>No items ready for pickup</p></div>'}
        </div>
      </div>
    </div>

    <div class="card" style="margin-top: 0;">
