app.get('/catalog', requireAuth, (req, res) => {
  const user = req.user;
  const search = (req.query.q || '').toLowerCase();
  const filtered = search ? catalog.filter(b =>
    b.title.toLowerCase().includes(search) ||
    b.author.toLowerCase().includes(search) ||
    b.genre.toLowerCase().includes(search)
  ) : catalog;

  res.send(renderLayout(user, 'catalog', 'Catalog', `
    <div class="page-header">
      <h2>Book Catalog</h2>
      <p>Browse our collection of ${catalog.length} titles</p>
    </div>

    <div class="card">
      <div class="card-body" style="padding: 16px 24px;">
        <form method="GET" action="/catalog" class="search-bar" style="margin-bottom: 0;">
          <input type="text" name="q" placeholder="Search by title, author, or genre..." value="${req.query.q || ''}" />
          <button type="submit" class="btn btn-secondary">🔍 Search</button>
        </form>
      </div>
    </div>

    <div class="card">
      <div class="card-body" style="padding: 0;">
        <table>
          <thead>
            <tr>
              <th>Title</th>
              <th>Author</th>
              <th>Year</th>
              <th>Genre</th>
              <th>Rating</th>
              <th>Availability</th>
            </tr>
          </thead>
          <tbody>
            ${filtered.map(b => `
              <tr>
                <td style="font-weight: 600;">${b.title}</td>
                <td style="color: var(--text-secondary);">${b.author}</td>
                <td>${b.year}</td>
                <td><span class="genre-tag">${b.genre}</span></td>
                <td><span class="rating">★ ${b.rating}</span></td>
                <td>
                  <span class="availability-dot ${b.available ? 'available' : 'unavailable'}"></span>
                  ${b.available ? `${b.copies - b.checkedOut}/${b.copies} available` : 'All copies out'}
                </td>
              </tr>
            `).join('')}
          </tbody>
        </table>
        ${filtered.length === 0 ? '<div class="empty-state"><span class="icon">🔍</span><p>No books found matching your search</p></div>' : ''}
      </div>
    </div>
  `));
});

