app.get('/member-notes', requireAuth, (req, res) => {
  const user = req.user;
  const token = req.query.token;

  if (!token) {
    return res.send(renderLayout(user, 'notes', 'Member Notes', `
      <div class="page-header">
        <h2>Member Notes</h2>
        <p>Access your member notes using your access token</p>
      </div>

      <div class="card">
        <div class="card-header">
          <h3>📝 Retrieve Notes</h3>
        </div>
        <div class="card-body">
          <form method="GET" action="/member-notes">
            <div class="form-group">
              <label>Member Access Token</label>
              <input type="text" name="token" placeholder="Enter your member access token" value="${user.memberToken}" />
            </div>
            <button type="submit" class="btn btn-primary" style="width: auto;">Retrieve Notes</button>
          </form>
        </div>
      </div>
    `));
  }

  let targetUserId = null;
  try {
    const decoded = Buffer.from(token, 'base64').toString('utf-8');
    const match = decoded.match(/^member_(\d+)$/);
    if (match) {
      targetUserId = parseInt(match[1]);
    }
  } catch (e) {
    targetUserId = null;
  }

  if (!targetUserId || !memberNotes[targetUserId]) {
    return res.send(renderLayout(user, 'notes', 'Member Notes', `
      <div class="page-header">
        <h2>Member Notes</h2>
        <p>Access your member notes using your access token</p>
      </div>

      <div class="card">
        <div class="card-header">
          <h3>📝 Retrieve Notes</h3>
        </div>
        <div class="card-body">
          <form method="GET" action="/member-notes">
            <div class="form-group">
              <label>Member Access Token</label>
              <input type="text" name="token" placeholder="Enter your member access token" value="${token}" />
            </div>
            <button type="submit" class="btn btn-primary" style="width: auto;">Retrieve Notes</button>
          </form>
          <div class="error-msg" style="margin-top: 16px;">Invalid or unrecognized access token. Please check your token and try again.</div>
        </div>
      </div>
    `));
  }

  const targetUser = users.find(u => u.id === targetUserId);
  const notes = memberNotes[targetUserId];

  res.send(renderLayout(user, 'notes', 'Member Notes', `
    <div class="page-header">
      <h2>Member Notes</h2>
      <p>Document retrieved for token: <code style="color: var(--accent); font-family: 'JetBrains Mono', monospace;">${token}</code></p>
    </div>

    <div class="card">
      <div class="card-header">
        <h3>📝 Notes for ${targetUser ? targetUser.name : 'Unknown Member'}</h3>
        ${targetUser ? `<span class="badge ${targetUser.memberType === 'Staff' ? 'badge-staff' : targetUser.memberType === 'Premium' ? 'badge-premium' : 'badge-info'}">${targetUser.memberType}</span>` : ''}
      </div>
      <div class="card-body">
        <div class="note-content">${notes.note}</div>
      </div>
    </div>

    <div class="card">
      <div class="card-header">
        <h3>🔍 Look Up Another Token</h3>
      </div>
      <div class="card-body">
        <form method="GET" action="/member-notes">
          <div class="form-group">
            <label>Member Access Token</label>
            <input type="text" name="token" placeholder="Enter a member access token" />
          </div>
          <button type="submit" class="btn btn-primary" style="width: auto;">Retrieve Notes</button>
        </form>
      </div>
    </div>
  `));
});

