.nav-btn-primary:hover { filter: brightness(1.1); box-shadow: 0 4px 16px rgba(255,107,53,0.4) !important; transform: translateY(-1px); }
.nav-user {
  display: flex;
  align-items: center;
  gap: 10px;
  color: rgba(255,255,255,0.9);
  font-size: 0.85rem;
}
.nav-user .user-avatar {
  width: 34px;
  height: 34px;
  background: linear-gradient(135deg, var(--primary), var(--teal));
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  color: #fff;
  box-shadow: 0 2px 8px rgba(0,180,160,0.3);
  border: 2px solid rgba(255,255,255,0.15);
}
.role-badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 5px;
  font-size: 0.65rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.role-badge-user { background: rgba(0,180,160,0.15); color: var(--teal); border: 1px solid rgba(0,180,160,0.3); }
.role-badge-admin { background: rgba(255,107,53,0.15); color: var(--accent); border: 1px solid rgba(255,107,53,0.3); }

/* ===== LAYOUT ===== */
.container { max-width: 1200px; margin: 0 auto; padding: 32px 24px; }
.container-sm { max-width: 480px; margin: 0 auto; padding: 32px 24px; }

/* ===== CARDS ===== */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
}
.card:hover { box-shadow: var(--shadow-md); }

/* ===== PAGE HEADERS ===== */
.page-header { margin-bottom: 28px; }
.page-title { font-size: 1.6rem; font-weight: 800; margin-bottom: 4px; letter-spacing: -0.5px; }
.page-subtitle { font-size: 0.9rem; color: var(--text-light); margin-bottom: 24px; }
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.78rem;
  color: var(--text-light);
  margin-bottom: 16px;
}
.breadcrumb a { color: var(--text-light); }
.breadcrumb a:hover { color: var(--primary); }
.breadcrumb .sep { opacity: 0.4; }

/* ===== BUTTONS ===== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 10px 20px;
  border-radius: var(--radius);
  font-size: 0.87rem;
  font-weight: 600;
  cursor: pointer;
  border: none;
  transition: all var(--transition-fast);
  text-decoration: none;
  text-align: center;
  font-family: var(--font);
  position: relative;
  overflow: hidden;
}
.btn::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(255,255,255,0.1) 0%, transparent 50%);
  pointer-events: none;
}
.btn:active { transform: scale(0.97); }
.btn-primary { background: linear-gradient(135deg, var(--primary), var(--primary-light)); color: #fff; box-shadow: 0 2px 8px rgba(0,102,204,0.25); }
.btn-primary:hover { filter: brightness(1.08); box-shadow: var(--shadow-glow-primary); color: #fff; transform: translateY(-1px); }
.btn-accent { background: linear-gradient(135deg, var(--accent), var(--accent-light)); color: #fff; box-shadow: 0 2px 8px rgba(255,107,53,0.25); }
.btn-accent:hover { filter: brightness(1.08); box-shadow: var(--shadow-glow-accent); color: #fff; transform: translateY(-1px); }
.btn-outline { background: transparent; border: 2px solid var(--primary); color: var(--primary); }
.btn-outline::after { display: none; }
.btn-outline:hover { background: var(--primary); color: #fff; box-shadow: var(--shadow-glow-primary); }
.btn-sm { padding: 6px 14px; font-size: 0.8rem; border-radius: 6px; }
.btn-teal { background: linear-gradient(135deg, var(--teal), var(--teal-light)); color: #fff; box-shadow: 0 2px 8px rgba(0,180,160,0.25); }
.btn-teal:hover { filter: brightness(1.08); color: #fff; box-shadow: var(--shadow-glow-teal); transform: translateY(-1px); }
.btn-coral { background: linear-gradient(135deg, var(--coral), var(--coral-light)); color: #fff; box-shadow: 0 2px 8px rgba(231,76,60,0.2); }
.btn-coral:hover { filter: brightness(1.08); color: #fff; transform: translateY(-1px); }
.btn-ghost { background: var(--bg-white); color: var(--text-mid); border: 1px solid var(--border); }
.btn-ghost::after { display: none; }
.btn-ghost:hover { border-color: var(--primary); color: var(--primary); background: var(--primary-ultralight); }
.btn-loading { pointer-events: none; opacity: 0.7; }
.btn-loading::before { content: ''; width: 14px; height: 14px; border: 2px solid rgba(255,255,255,0.3); border-top-color: #fff; border-radius: 50%; animation: spin 0.6s linear infinite; margin-right: 6px; }
@keyframes spin { to { transform: rotate(360deg); } }

/* ===== STATS ===== */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 28px;
}
.stat-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 22px;
  text-align: center;
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
  position: relative;
  overflow: hidden;
}
.stat-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  border-radius: 12px 12px 0 0;
}
.stat-card:hover { transform: translateY(-2px); box-shadow: var(--shadow-lg); }
.stat-card:nth-child(1)::before { background: linear-gradient(90deg, var(--primary), var(--primary-light)); }
.stat-card:nth-child(2)::before { background: linear-gradient(90deg, var(--accent), var(--accent-light)); }
.stat-card:nth-child(3)::before { background: linear-gradient(90deg, var(--teal), var(--teal-light)); }
.stat-card:nth-child(4)::before { background: linear-gradient(90deg, var(--amber), var(--amber-light)); }
.stat-value {
  font-size: 2rem;
  font-weight: 800;
  margin-bottom: 4px;
  letter-spacing: -1px;
}
.stat-value.blue { color: var(--primary); }
.stat-value.accent { color: var(--accent); }
.stat-value.teal { color: var(--teal); }
.stat-value.amber { color: var(--amber); }
.stat-label {
  font-size: 0.72rem;
  color: var(--text-light);
  text-transform: uppercase;
  letter-spacing: 0.8px;
  font-weight: 600;
}

/* ===== TABLES ===== */
.data-table-wrapper {
  overflow-x: auto;
  border-radius: var(--radius-lg);
}
.data-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
}
.data-table th {
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  color: var(--text-light);
  padding: 14px 16px;
  text-align: left;
  border-bottom: 2px solid var(--border);
  font-weight: 700;
  background: linear-gradient(180deg, var(--bg-light) 0%, #EDF1F7 100%);
  position: sticky;
  top: 0;
}
.data-table th:first-child { border-radius: var(--radius) 0 0 0; }
.data-table th:last-child { border-radius: 0 var(--radius) 0 0; }
.data-table td {
  padding: 12px 16px;
  font-size: 0.87rem;
  border-bottom: 1px solid var(--border-light);
  transition: background var(--transition-fast);
}
.data-table tbody tr { transition: all var(--transition-fast); }
.data-table tbody tr:hover {
  background: rgba(0,102,204,0.03);
}
.data-table tbody tr:hover td {
  border-bottom-color: rgba(0,102,204,0.1);
}
.data-table tbody tr:nth-child(even) td {
  background: rgba(245,247,250,0.6);
}
.data-table tbody tr:nth-child(even):hover td {
  background: rgba(0,102,204,0.05);
}

/* ===== STATUS BADGES ===== */
.status-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 0.72rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}
.status-badge::before {
  content: '';
  width: 6px;
  height: 6px;
  border-radius: 50%;
}
.status-confirmed { background: rgba(0,180,160,0.1); color: var(--teal); border: 1px solid rgba(0,180,160,0.2); }
.status-confirmed::before { background: var(--teal); }
.status-completed { background: rgba(0,102,204,0.1); color: var(--primary); border: 1px solid rgba(0,102,204,0.2); }
.status-completed::before { background: var(--primary); }
.status-cancelled { background: rgba(231,76,60,0.1); color: var(--coral); border: 1px solid rgba(231,76,60,0.2); }
.status-cancelled::before { background: var(--coral); }
.status-pending { background: rgba(255,176,32,0.1); color: #D4920C; border: 1px solid rgba(255,176,32,0.2); }
.status-pending::before { background: var(--amber); }

/* ===== FORMS ===== */
.form-group { margin-bottom: 18px; }
.form-group label {
  display: block;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text-mid);
  margin-bottom: 6px;
  letter-spacing: 0.2px;
}
.form-group input, .form-group select {
  width: 100%;
  padding: 11px 14px;
  border: 1.5px solid var(--border);
  border-radius: var(--radius);
  font-size: 0.9rem;
  font-family: var(--font);
  color: var(--text-dark);
  background: #fff;
  transition: all var(--transition-fast);
}
.form-group input:hover, .form-group select:hover {
  border-color: #CBD5E0;
}
.form-group input:focus, .form-group select:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(0,102,204,0.12), var(--shadow-sm);
}
.form-group input::placeholder { color: #A0AEC0; }
.form-divider {
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 20px 0;
  color: var(--text-light);
  font-size: 0.78rem;
}
.form-divider::before, .form-divider::after { content: ''; flex: 1; height: 1px; background: var(--border); }

/* ===== MESSAGES ===== */
.error-msg {
  padding: 14px 18px;
  background: linear-gradient(135deg, rgba(231,76,60,0.06), rgba(231,76,60,0.1));
  border: 1px solid rgba(231,76,60,0.2);
  border-left: 4px solid var(--coral);
  border-radius: var(--radius);
  color: #C0392B;
  font-size: 0.85rem;
  margin-bottom: 18px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.error-msg::before { content: '⚠'; font-size: 1rem; }
.success-msg {
  padding: 14px 18px;
  background: linear-gradient(135deg, rgba(0,180,160,0.06), rgba(0,180,160,0.1));
  border: 1px solid rgba(0,180,160,0.2);
  border-left: 4px solid var(--teal);
  border-radius: var(--radius);
  color: #00866E;
  font-size: 0.85rem;
  margin-bottom: 18px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.success-msg::before { content: '✓'; font-size: 1rem; font-weight: 700; }

/* ===== FLAG BANNER ===== */
.flag-banner {
  background: linear-gradient(135deg, var(--accent) 0%, #FF4500 50%, #E8390A 100%);
  color: #fff;
  padding: 28px 32px;
  border-radius: var(--radius-xl);
  margin-bottom: 32px;
  box-shadow: 0 8px 32px rgba(255,107,53,0.35), inset 0 1px 0 rgba(255,255,255,0.2);
  text-align: center;
  position: relative;
  overflow: hidden;
}
.flag-banner::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(ellipse at 30% 50%, rgba(255,255,255,0.1) 0%, transparent 50%);
  pointer-events: none;
}
.flag-banner h2 { font-size: 1.15rem; margin-bottom: 12px; font-weight: 700; position: relative; }
.flag-banner .flag-value {
  font-family: 'Courier New', monospace;
  font-size: 1.35rem;
  font-weight: 700;
  background: rgba(0,0,0,0.25);
  padding: 10px 24px;
  border-radius: var(--radius);
  display: inline-block;
  letter-spacing: 1.5px;
  position: relative;
  border: 1px solid rgba(255,255,255,0.15);
  backdrop-filter: blur(4px);
}

/* ===== HERO ===== */
.hero {
  background: linear-gradient(135deg, var(--navy) 0%, #0A1628 30%, #0D2137 60%, var(--primary-dark) 100%);
  color: #fff;
  padding: 90px 24px 80px;
  text-align: center;
  position: relative;
  overflow: hidden;
}
.hero::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(ellipse at 25% 40%, rgba(0,102,204,0.18) 0%, transparent 55%),
              radial-gradient(ellipse at 75% 20%, rgba(255,107,53,0.12) 0%, transparent 50%),
              radial-gradient(ellipse at 50% 80%, rgba(0,180,160,0.08) 0%, transparent 40%);
  pointer-events: none;
  animation: heroPulse 8s ease-in-out infinite alternate;
}
@keyframes heroPulse {
  0% { opacity: 1; }
  100% { opacity: 0.7; transform: scale(1.05); }
}
.hero::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 80px;
  background: linear-gradient(180deg, transparent, var(--bg-light));
  pointer-events: none;
}
.hero h1 {
  font-size: 3rem;
  font-weight: 900;
  margin-bottom: 14px;
  position: relative;
  letter-spacing: -1px;
  line-height: 1.15;
}
.hero h1 span { color: var(--accent); }
.hero p {
  font-size: 1.1rem;
  color: rgba(255,255,255,0.7);
  max-width: 600px;
  margin: 0 auto 36px;
  position: relative;
  line-height: 1.7;
}
.hero-stats {
  display: flex;
  justify-content: center;
  gap: 40px;
  margin-top: 40px;
  position: relative;
}
.hero-stat { text-align: center; }
.hero-stat-value { font-size: 1.8rem; font-weight: 800; color: #fff; }
.hero-stat-label { font-size: 0.75rem; color: rgba(255,255,255,0.55); text-transform: uppercase; letter-spacing: 1px; font-weight: 600; }

/* ===== SEARCH BAR HERO ===== */
.search-bar-hero {
  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: var(--radius-xl);
  padding: 22px 26px;
  max-width: 820px;
  margin: 0 auto;
  display: flex;
  gap: 12px;
  align-items: end;
  position: relative;
  box-shadow: 0 8px 32px rgba(0,0,0,0.2);
}
.search-bar-hero .form-group { margin-bottom: 0; flex: 1; }
.search-bar-hero label { color: rgba(255,255,255,0.65); font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.5px; }
.search-bar-hero input {
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.15);
  color: #fff;
  border-radius: var(--radius);
}
.search-bar-hero input::placeholder { color: rgba(255,255,255,0.35); }
.search-bar-hero input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(255,107,53,0.2);
  background: rgba(255,255,255,0.14);
}

/* ===== DEALS SECTION ===== */
.deals-section { padding: 70px 24px 60px; }
.deals-section h2 { text-align: center; font-size: 1.7rem; font-weight: 800; margin-bottom: 8px; letter-spacing: -0.5px; }
.deals-section .section-sub { text-align: center; color: var(--text-light); margin-bottom: 44px; font-size: 0.95rem; }
.deals-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 20px;
  max-width: 1200px;
  margin: 0 auto;
}
.deal-card {
  background: #fff;
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
}
.deal-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); }
.deal-card-img {
  height: 160px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 3rem;
  position: relative;
}
.deal-card-img::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 40px;
  background: linear-gradient(180deg, transparent, rgba(0,0,0,0.05));
}
.deal-card-body { padding: 20px; }
.deal-card-body h3 { font-size: 1.05rem; font-weight: 700; margin-bottom: 4px; }
.deal-card-body .deal-route { font-size: 0.82rem; color: var(--text-light); margin-bottom: 12px; }
.deal-card-body .deal-price { font-size: 1.4rem; font-weight: 800; color: var(--accent); }
.deal-card-body .deal-price span { font-size: 0.8rem; font-weight: 500; color: var(--text-light); }

/* ===== FEATURES SECTION ===== */
.features-section { padding: 70px 24px; }
.feature-card {
  text-align: center;
  padding: 36px 24px;
  background: #fff;
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
}
.feature-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-lg); border-color: var(--primary-ultralight); }
.feature-icon {
  font-size: 2.5rem;
  margin-bottom: 16px;
  display: inline-block;
  animation: featureBounce 3s ease-in-out infinite;
}
.feature-card:nth-child(2) .feature-icon { animation-delay: 0.3s; }
.feature-card:nth-child(3) .feature-icon { animation-delay: 0.6s; }
@keyframes featureBounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

/* ===== TESTIMONIALS ===== */
.testimonials {
  background: linear-gradient(135deg, var(--navy) 0%, #0A1628 50%, var(--navy-mid) 100%);
  color: #fff;
  padding: 70px 24px;
  position: relative;
}
.testimonials::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255,107,53,0.3), transparent);
}
.testimonials h2 { text-align: center; font-size: 1.6rem; font-weight: 800; margin-bottom: 44px; }
.testimonials-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 20px;
  max-width: 1000px;
  margin: 0 auto;
}
.testimonial-card {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: var(--radius-lg);
  padding: 28px;
  transition: all var(--transition);
  position: relative;
}
.testimonial-card::before {
  content: '"';
  position: absolute;
  top: 16px;
  left: 20px;
  font-size: 3rem;
  color: rgba(255,107,53,0.15);
  font-family: Georgia, serif;
  line-height: 1;
}
.testimonial-card:hover { background: rgba(255,255,255,0.07); border-color: rgba(255,255,255,0.15); transform: translateY(-2px); }
.testimonial-card p { font-size: 0.9rem; color: rgba(255,255,255,0.8); margin-bottom: 16px; line-height: 1.7; font-style: italic; position: relative; z-index: 1; }
.testimonial-card .tc-author { font-size: 0.82rem; font-weight: 600; color: var(--accent); }
.testimonial-card .tc-stars { color: var(--amber); font-size: 0.8rem; margin-bottom: 4px; letter-spacing: 2px; }

/* ===== FOOTER ===== */
.footer {
  background: linear-gradient(180deg, var(--navy) 0%, #080E1A 100%);
  border-top: 1px solid rgba(255,255,255,0.06);
  color: rgba(255,255,255,0.45);
  padding: 48px 24px 32px;
  font-size: 0.82rem;
}
.footer-grid {
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 40px;
  margin-bottom: 32px;
}
.footer-col h4 {
  color: rgba(255,255,255,0.85);
  font-size: 0.85rem;
  font-weight: 700;
  margin-bottom: 16px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.footer-col p { line-height: 1.7; margin-bottom: 8px; }
.footer-col a { color: rgba(255,255,255,0.5); display: block; padding: 3px 0; transition: color var(--transition-fast); }
.footer-col a:hover { color: var(--accent); }
.footer-bottom {
  max-width: 1200px;
  margin: 0 auto;
  padding-top: 24px;
  border-top: 1px solid rgba(255,255,255,0.06);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
}
.footer-bottom .footer-brand { color: rgba(255,255,255,0.65); font-weight: 600; }
.footer-bottom .footer-brand span { color: var(--accent); }

/* ===== ACCESS DENIED ===== */
.access-denied {
  text-align: center;
  padding: 80px 24px;
}
.access-denied h1 {
  font-size: 5rem;
  font-weight: 900;
  background: linear-gradient(135deg, var(--coral), var(--accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 8px;
}
.access-denied p { font-size: 1.1rem; color: var(--text-light); margin-bottom: 12px; }
.access-denied .lock-icon { font-size: 3rem; margin-bottom: 16px; opacity: 0.6; }

/* ===== HOTEL CARD ===== */
.hotel-card-img {
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2.5rem;
  background: linear-gradient(135deg, var(--bg-light) 0%, #E0E7F0 100%);
  border-bottom: 1px solid var(--border-light);
}

/* ===== TABS ===== */
.tabs {
  display: flex;
  gap: 4px;
  margin-bottom: 24px;
  background: var(--bg-white);
  border-radius: var(--radius-lg);
  padding: 4px;
  border: 1px solid var(--border);
  width: fit-content;
  box-shadow: var(--shadow-xs);
}
.tab {
  padding: 9px 22px;
  border-radius: var(--radius);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  border: none;
  background: transparent;
  color: var(--text-mid);
  transition: all var(--transition-fast);
  text-decoration: none;
  font-family: var(--font);
}
.tab.active {
  background: linear-gradient(135deg, var(--primary), var(--primary-light));
  color: #fff;
  box-shadow: 0 2px 8px rgba(0,102,204,0.25);
}
.tab:hover:not(.active) {
  background: var(--bg-light);
  color: var(--primary);
}

/* ===== DASHBOARD ===== */
.dashboard-grid {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 24px;
}
.dashboard-grid-full { grid-column: 1 / -1; }

.welcome-banner {
  background: linear-gradient(135deg, var(--primary) 0%, #003D7A 50%, var(--primary-dark) 100%);
  color: #fff;
  padding: 32px 36px;
  border-radius: var(--radius-xl);
  margin-bottom: 28px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: 0 8px 32px rgba(0,102,204,0.25);
  position: relative;
  overflow: hidden;
}
.welcome-banner::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -20%;
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(255,255,255,0.06) 0%, transparent 70%);
  pointer-events: none;
}
.welcome-banner h1 { font-size: 1.5rem; font-weight: 700; margin-bottom: 6px; position: relative; }
.welcome-banner p { color: rgba(255,255,255,0.75); font-size: 0.9rem; position: relative; }

.points-card {
  background: linear-gradient(135deg, var(--accent) 0%, #E85D1A 50%, #D44F12 100%);
  color: #fff;
  padding: 28px;
  border-radius: var(--radius-xl);
  text-align: center;
  box-shadow: 0 8px 32px rgba(255,107,53,0.3);
  position: relative;
  overflow: hidden;
}
.points-card::before {
  content: '';
  position: absolute;
  top: -30%;
  left: -30%;
  width: 160%;
  height: 160%;
  background: radial-gradient(circle at 30% 30%, rgba(255,255,255,0.1) 0%, transparent 60%);
  pointer-events: none;
}
.points-value { font-size: 2.8rem; font-weight: 900; position: relative; letter-spacing: -1px; }
.points-label { font-size: 0.8rem; opacity: 0.85; text-transform: uppercase; letter-spacing: 1.5px; font-weight: 600; position: relative; margin-top: 4px; }

.activity-item {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 0;
  border-bottom: 1px solid var(--border-light);
  transition: all var(--transition-fast);
}
.activity-item:last-child { border-bottom: none; }
.activity-item:hover { padding-left: 6px; }
.activity-icon {
  width: 38px;
  height: 38px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  flex-shrink: 0;
}
.activity-text { font-size: 0.85rem; color: var(--text-mid); font-weight: 500; }
.activity-time { font-size: 0.73rem; color: var(--text-light); margin-top: 1px; }

/* ===== FLIGHT & HOTEL CARDS ===== */
.flight-card, .hotel-result-card {
  background: #fff;
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 22px;
  margin-bottom: 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
  position: relative;
}
.flight-card::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 0;
  background: linear-gradient(180deg, var(--primary), var(--teal));
  border-radius: 0 3px 3px 0;
  transition: height var(--transition);
}
.flight-card:hover::before { height: 60%; }
.flight-card:hover, .hotel-result-card:hover {
  box-shadow: var(--shadow-lg);
  border-color: rgba(0,102,204,0.2);
  transform: translateX(2px);
}
.flight-info h3 { font-size: 1rem; font-weight: 700; margin-bottom: 4px; }
.flight-info .flight-detail { font-size: 0.82rem; color: var(--text-light); line-height: 1.6; }
.flight-price { font-size: 1.6rem; font-weight: 800; color: var(--accent); text-align: right; }
.flight-price .per { font-size: 0.75rem; color: var(--text-light); font-weight: 500; }

.stars { color: var(--amber); letter-spacing: 2px; }

/* ===== SEARCH PANEL ===== */
.search-panel {
  background: #fff;
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 26px;
  margin-bottom: 28px;
  box-shadow: var(--shadow-sm);
  position: relative;
  overflow: hidden;
}
.search-panel::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--primary), var(--accent), var(--teal));
}
.search-panel .search-row {
  display: flex;
  gap: 12px;
  align-items: end;
  flex-wrap: wrap;
}
.search-panel .search-row .form-group { flex: 1; min-width: 140px; margin-bottom: 0; }

.map-placeholder {
  background: linear-gradient(135deg, #E8EDF5 0%, #D5DCE6 50%, #C8D1DE 100%);
  border-radius: var(--radius-lg);
  height: 200px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--text-light);
  font-size: 0.9rem;
  margin-top: 28px;
  border: 1px solid var(--border);
  gap: 8px;
}
.map-placeholder span { font-size: 2.5rem; }

/* ===== BOOKING CARDS ===== */
.booking-card {
  background: #fff;
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 22px;
  margin-bottom: 16px;
  box-shadow: var(--shadow-sm);
  transition: all var(--transition);
}
.booking-card:hover { box-shadow: var(--shadow-lg); transform: translateY(-2px); }
.booking-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 14px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border-light);
}
.booking-conf { font-weight: 700; font-size: 1rem; color: var(--primary); font-family: 'Courier New', monospace; }
.booking-details { display: flex; gap: 32px; flex-wrap: wrap; }
.booking-detail label { display: block; font-size: 0.7rem; text-transform: uppercase; letter-spacing: 0.5px; color: var(--text-light); font-weight: 600; margin-bottom: 2px; }
.booking-detail span { font-size: 0.88rem; font-weight: 500; }
.booking-actions { display: flex; gap: 8px; margin-top: 18px; padding-top: 14px; border-top: 1px solid var(--border-light); }

/* ===== LOGIN PAGE SPECIFIC ===== */
.auth-page-bg {
  min-height: calc(100vh - 64px);
  background: linear-gradient(135deg, var(--bg-light) 0%, #E0E7F0 50%, #D5DCE6 100%);
  display: flex;
  flex-direction: column;
  position: relative;
}
.auth-page-bg::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(ellipse at 30% 20%, rgba(0,102,204,0.06) 0%, transparent 50%),
              radial-gradient(ellipse at 70% 80%, rgba(255,107,53,0.04) 0%, transparent 50%);
  pointer-events: none;
}
.auth-card {
  background: var(--bg-white);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 40px;
  box-shadow: var(--shadow-lg);
  position: relative;
  overflow: hidden;
}
.auth-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, var(--primary), var(--accent));
}
.auth-logo {
  text-align: center;
  margin-bottom: 24px;
}
.auth-logo .auth-logo-icon {
  width: 52px;
  height: 52px;
  background: linear-gradient(135deg, var(--primary), var(--accent));
  border-radius: 14px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 24px;
  box-shadow: 0 4px 16px rgba(0,102,204,0.25);
  margin-bottom: 12px;
}

/* ===== ANIMATIONS ===== */
.fade-in { animation: fadeIn 0.4s ease-out; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

.slide-up { animation: slideUp 0.5s ease-out; }
@keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }

.stagger-1 { animation-delay: 0.05s; animation-fill-mode: both; }
.stagger-2 { animation-delay: 0.1s; animation-fill-mode: both; }
.stagger-3 { animation-delay: 0.15s; animation-fill-mode: both; }
.stagger-4 { animation-delay: 0.2s; animation-fill-mode: both; }

/* ===== EMPTY STATE ===== */
.empty-state {
  text-align: center;
  padding: 48px 24px;
  color: var(--text-light);
}
.empty-state-icon { font-size: 3rem; margin-bottom: 16px; opacity: 0.5; }
.empty-state h3 { font-size: 1.1rem; color: var(--text-mid); margin-bottom: 8px; }
.empty-state p { font-size: 0.9rem; margin-bottom: 20px; }

/* ===== RESPONSIVE ===== */
@media (max-width: 1024px) {
  .dashboard-grid { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr 1fr; gap: 24px; }
}
@media (max-width: 768px) {
  .navbar { padding: 0 16px; }
  .navbar .logo { margin-right: 16px; }
  .nav-links { gap: 0; overflow-x: auto; }
  .nav-links a { padding: 8px 10px; font-size: 0.8rem; white-space: nowrap; }
  .hero { padding: 60px 16px 50px; }
  .hero h1 { font-size: 2rem; }
  .hero p { font-size: 0.95rem; }
  .search-bar-hero { flex-direction: column; padding: 16px; }
  .search-bar-hero .form-group { width: 100%; }
  .hero-stats { gap: 24px; }
  .hero-stat-value { font-size: 1.4rem; }
  .deals-grid { grid-template-columns: 1fr; }
  .features-grid { grid-template-columns: 1fr !important; }
  .testimonials-grid { grid-template-columns: 1fr; }
  .container { padding: 24px 16px; }
  .container-sm { padding: 24px 16px; }
  .search-panel .search-row { flex-direction: column; }
  .search-panel .search-row .form-group { min-width: 100%; }
  .flight-card, .hotel-result-card { flex-direction: column; align-items: stretch; gap: 16px; }
  .stats-grid { grid-template-columns: 1fr 1fr; }
  .booking-details { gap: 16px; }
  .welcome-banner { flex-direction: column; gap: 16px; text-align: center; }
  .footer-grid { grid-template-columns: 1fr; }
  .footer-bottom { flex-direction: column; text-align: center; }
  .data-table { font-size: 0.82rem; }
  .data-table th, .data-table td { padding: 10px 10px; }
  .nav-user span:not(.role-badge) { display: none; }
}
@media (max-width: 480px) {
  html { font-size: 14px; }
  .hero h1 { font-size: 1.7rem; }
  .nav-links a { padding: 8px 8px; font-size: 0.75rem; }
  .auth-card { padding: 28px 20px; }
  .stats-grid { grid-template-columns: 1fr; }
}
`;

function renderNav(user) {
  if (!user) {
    return `
    <nav class="navbar">
      <a href="/" class="logo"><div class="logo-icon">✈</div> Sky<span>Voyage</span></a>
      <div class="nav-links">
        <a href="/flights">Flights</a>
        <a href="/hotels">Hotels</a>
      </div>
      <div class="nav-right">
        <a href="/login">Sign In</a>
        <a href="/register" class="nav-btn-primary">Get Started</a>
      </div>
    </nav>`;
  }
  const init = esc(user.name).split(' ').map(n => n[0]).join('');
  const roleBadgeClass = user.role === 'admin' ? 'role-badge-admin' : 'role-badge-user';
  const adminLink = user.role === 'admin' ? '<a href="/admin">Admin Panel</a>' : '';
  return `
  <nav class="navbar">
    <a href="/" class="logo"><div class="logo-icon">✈</div> Sky<span>Voyage</span></a>
    <div class="nav-links">
      <a href="/flights">Flights</a>
      <a href="/hotels">Hotels</a>
      <a href="/bookings">My Bookings</a>
      <a href="/dashboard">Dashboard</a>
      ${adminLink}
    </div>
    <div class="nav-right">
      <div class="nav-user">
        <div class="user-avatar">${init}</div>
        <span>${esc(user.name)}</span>
        <span class="role-badge ${roleBadgeClass}">${esc(user.role)}</span>
      </div>
      <a href="/logout">Logout</a>
    </div>
  </nav>`;
}

function pageShell(title, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — SkyVoyage</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
${renderNav(user)}
${content}
</body></html>`;
}

