        <div class="container-sm" style="padding-top:48px;flex:1;position:relative;z-index:1;">
          <div class="auth-card">
            <div class="error-msg">Username "<strong>${esc(username)}</strong>" is already taken. Please choose another.</div>
            <a href="/register" class="btn btn-outline" style="width:100%;text-align:center;">Try Again</a>
          </div>
        </div>
      </div>`));
  }

  const name = body.name || username;
  const role = body.role || 'user';
  const loyaltyPoints = body.loyalty_points || 500;
  const createdAt = new Date().toISOString();

  db.run(
    'INSERT INTO users (username, password, name, role, loyalty_points, created_at) VALUES (?,?,?,?,?,?)',
    [username, password, name, role, loyaltyPoints, createdAt]
  );

  res.redirect('/login?msg=registered');
});

