app.get('/flights', (req, res) => {
  const userId = getSessionUserId(req);
  const user = userId ? getUser(userId) : null;

  const origin = req.query.origin || '';
  const destination = req.query.destination || '';
  const sort = req.query.sort || '';

  let query = 'SELECT * FROM flights WHERE 1=1';
  const params = [];
  if (origin) {
    query += ' AND UPPER(origin) = UPPER(?)';
    params.push(origin);
  }
  if (destination) {
    query += ' AND UPPER(destination) = UPPER(?)';
    params.push(destination);
  }
  if (sort === 'price_asc') query += ' ORDER BY price ASC';
  else if (sort === 'price_desc') query += ' ORDER BY price DESC';
  else query += ' ORDER BY departure_time ASC';

  const stmt = db.prepare(query);
  if (params.length > 0) stmt.bind(params);
  const flights = [];
  while (stmt.step()) {
    flights.push(stmt.getAsObject());
  }
  stmt.free();

  const airlineColors = {
    'SkyVoyage Air': 'var(--primary)',
    'Pacific Wings': 'var(--teal)',
    'Atlantic Express': 'var(--purple)',
  };

  const flightCards = flights.length > 0 ? flights.map((f, idx) => {
    const dep = new Date(f.departure_time);
    const arr = new Date(f.arrival_time);
    const diffMs = arr - dep;
    const hours = Math.floor(diffMs / 3600000);
    const mins = Math.floor((diffMs % 3600000) / 60000);
    const seatsClass = f.seats_available <= 10 ? 'color:var(--coral);font-weight:600;' : 'color:var(--text-light);';
    const airlineColor = airlineColors[f.airline] || 'var(--text-mid)';
    return `
    <div class="flight-card slide-up" style="animation-delay:${idx * 0.05}s;animation-fill-mode:both;">
      <div class="flight-info">
        <h3 style="display:flex;align-items:center;gap:8px;">
          <span style="color:${airlineColor};">${esc(f.airline)}</span>
          <span style="font-size:0.82rem;color:var(--text-light);font-weight:500;">—</span>
          <span style="font-family:'Courier New',monospace;font-size:0.9rem;color:var(--text-mid);">${esc(f.flight_number)}</span>
        </h3>
        <div class="flight-detail" style="margin-top:6px;">
          <strong>${esc(f.origin)}</strong> → <strong>${esc(f.destination)}</strong> · ${hours}h ${mins}m
        </div>
        <div class="flight-detail">
          📅 ${dep.toLocaleDateString('en-US', {weekday:'short', month:'short', day:'numeric', year:'numeric'})} · ${dep.toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'})}
        </div>
        <div class="flight-detail" style="${seatsClass}">
          💺 ${f.seats_available} seat${f.seats_available !== 1 ? 's' : ''} remaining${f.seats_available <= 10 ? ' — Book soon!' : ''}
        </div>
      </div>
      <div style="text-align:right;">
        <div class="flight-price">$${Number(f.price).toFixed(2)} <span class="per">/person</span></div>
        <div style="font-size:0.72rem;color:var(--text-light);margin-top:2px;">incl. taxes & fees</div>
        <a href="/flights" class="btn btn-accent btn-sm" style="margin-top:10px;">Select Flight →</a>
      </div>
    </div>`;
  }).join('') : `
    <div class="empty-state">
      <div class="empty-state-icon">✈️</div>
      <h3>No flights found</h3>
      <p>Try adjusting your search criteria or browsing all available routes.</p>
      <a href="/flights" class="btn btn-primary btn-sm">View All Flights</a>
    </div>`;

  res.send(pageShell('Flight Search', user, `
    <div class="container">
      <div class="breadcrumb">
        <a href="/">Home</a> <span class="sep">/</span> <span>Flights</span>
      </div>

      <h1 class="page-title">✈️ Flight Search</h1>
      <p class="page-subtitle">Find the perfect flight for your next adventure — ${flights.length > 0 ? flights.length + ' routes available' : 'search from 15+ routes'}</p>

      <div class="search-panel">
        <form method="GET" action="/flights">
          <div class="search-row">
            <div class="form-group">
              <label>Origin Airport</label>
              <input type="text" name="origin" placeholder="e.g. AUS, JFK, LAX" value="${esc(origin)}">
            </div>
            <div class="form-group">
              <label>Destination Airport</label>
              <input type="text" name="destination" placeholder="e.g. NRT, LHR, HNL" value="${esc(destination)}">
            </div>
            <div class="form-group">
              <label>Departure Date</label>
              <input type="date" name="departure_date">
            </div>
            <div class="form-group">
              <label>Return Date</label>
              <input type="date" name="return_date">
            </div>
            <div class="form-group" style="max-width:100px;">
              <label>Passengers</label>
              <input type="number" name="passengers" value="1" min="1" max="9">
            </div>
            <button type="submit" class="btn btn-primary" style="height:42px;white-space:nowrap;">Search Flights</button>
          </div>
        </form>
      </div>

      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;flex-wrap:wrap;gap:8px;">
        <p style="font-size:0.85rem;color:var(--text-light);font-weight:500;">${flights.length} flight(s) found ${origin ? 'from <strong>' + esc(origin.toUpperCase()) + '</strong>' : ''} ${destination ? 'to <strong>' + esc(destination.toUpperCase()) + '</strong>' : ''}</p>
        <div style="display:flex;gap:8px;">
          <a href="/flights?origin=${esc(origin)}&destination=${esc(destination)}&sort=price_asc" class="btn btn-sm ${sort === 'price_asc' ? 'btn-primary' : 'btn-ghost'}">Price ↑</a>
          <a href="/flights?origin=${esc(origin)}&destination=${esc(destination)}&sort=price_desc" class="btn btn-sm ${sort === 'price_desc' ? 'btn-primary' : 'btn-ghost'}">Price ↓</a>
