  const sort = req.query.sort || '';

  let query = 'SELECT * FROM hotels WHERE 1=1';
  const params = [];
  if (city) {
    query += ' AND UPPER(city) LIKE UPPER(?)';
    params.push('%' + city + '%');
  }
  if (sort === 'price_asc') query += ' ORDER BY price_per_night ASC';
  else if (sort === 'price_desc') query += ' ORDER BY price_per_night DESC';
  else if (sort === 'rating') query += ' ORDER BY star_rating DESC';
  else query += ' ORDER BY star_rating DESC';

  const stmt = db.prepare(query);
  if (params.length > 0) stmt.bind(params);
  const hotels = [];
  while (stmt.step()) {
    hotels.push(stmt.getAsObject());
  }
  stmt.free();

