app.get('/bookings', requireAuth, (req, res) => {
  const user = req.user;
  const tab = req.query.tab || 'upcoming';

  let whereClause = '';
  if (tab === 'past') {
    whereClause = "AND (b.status = 'completed' OR b.status = 'cancelled')";
  } else {
    whereClause = "AND b.status = 'confirmed'";
  }

  const stmt = db.prepare(`SELECT b.*, f.flight_number, f.origin, f.destination, f.airline, f.departure_time,
    h.name as hotel_name, h.city as hotel_city
    FROM bookings b
    LEFT JOIN flights f ON b.flight_id = f.id
    LEFT JOIN hotels h ON b.hotel_id = h.id
    WHERE b.user_id = ? ${whereClause}
    ORDER BY b.created_at DESC`);
  stmt.bind([user.id]);
  const bookings = [];
  while (stmt.step()) {
    bookings.push(stmt.getAsObject());
  }
  stmt.free();

  const bookingCards = bookings.length > 0 ? bookings.map((b, idx) => `
    <div class="booking-card slide-up" style="animation-delay:${idx * 0.05}s;animation-fill-mode:both;">
      <div class="booking-header">
        <span class="booking-conf">${esc(b.confirmation_code)}</span>
        <span class="status-badge status-${b.status}">${esc(b.status)}</span>
      </div>
      <div class="booking-details">
        ${b.flight_number ? `
        <div class="booking-detail">
          <label>Flight</label>
          <span>✈️ ${esc(b.airline)} ${esc(b.flight_number)}</span>
        </div>
        <div class="booking-detail">
          <label>Route</label>
          <span>${esc(b.origin)} → ${esc(b.destination)}</span>
        </div>` : ''}
        ${b.hotel_name ? `
        <div class="booking-detail">
          <label>Hotel</label>
          <span>🏨 ${esc(b.hotel_name)}</span>
        </div>
        <div class="booking-detail">
          <label>City</label>
          <span>📍 ${esc(b.hotel_city)}</span>
        </div>
        <div class="booking-detail">
          <label>Stay Dates</label>
          <span>📅 ${esc(b.check_in)} → ${esc(b.check_out)}</span>
        </div>` : ''}
        <div class="booking-detail">
          <label>Passengers</label>
          <span>👤 ${b.passengers}</span>
        </div>
        <div class="booking-detail">
          <label>Total Price</label>
          <span style="font-weight:700;color:var(--accent);font-size:1rem;">$${Number(b.total_price).toFixed(2)}</span>
        </div>
      </div>
      <div class="booking-actions">
        ${b.status === 'confirmed' ? '<button class="btn btn-coral btn-sm">Cancel Booking</button>' : ''}
        <button class="btn btn-ghost btn-sm">📄 Download Itinerary</button>
        <button class="btn btn-ghost btn-sm">📧 Email Confirmation</button>
      </div>
    </div>
  `).join('') : `
    <div class="empty-state">
      <div class="empty-state-icon">${tab === 'past' ? '📜' : '🧳'}</div>
      <h3>${tab === 'past' ? 'No past bookings' : 'No upcoming bookings'}</h3>
      <p>${tab === 'past' ? 'Your completed and cancelled trips will appear here.' : 'Start planning your next adventure!'}</p>
      <div style="display:flex;gap:8px;justify-content:center;">
        <a href="/flights" class="btn btn-primary btn-sm">Search Flights →</a>
        <a href="/hotels" class="btn btn-teal btn-sm">Find Hotels →</a>
      </div>
    </div>`;

  res.send(pageShell('My Bookings', user, `
    <div class="container">
      <div class="breadcrumb">
        <a href="/">Home</a> <span class="sep">/</span> <a href="/dashboard">Dashboard</a> <span class="sep">/</span> <span>Bookings</span>
      </div>

      <h1 class="page-title">📋 My Bookings</h1>
      <p class="page-subtitle">View and manage all your travel reservations</p>

      <div class="tabs">
        <a href="/bookings?tab=upcoming" class="tab ${tab === 'upcoming' ? 'active' : ''}">🛫 Upcoming</a>
        <a href="/bookings?tab=past" class="tab ${tab === 'past' ? 'active' : ''}">📜 Past</a>
      </div>

      ${bookingCards}
    </div>
    ${renderFooter()}
  `));
});

app.get('/admin', requireAuth, (req, res) => {
  const user = req.user;

  if (user.role !== 'admin') {
    return res.status(403).send(pageShell('Access Denied', user, `
      <div class="container">
        <div class="access-denied">
          <div class="lock-icon">🔒</div>
          <h1>403</h1>
          <p style="font-size:1.2rem;font-weight:600;color:var(--text-dark);margin-bottom:6px;">Access Denied</p>
          <p style="font-size:0.9rem;color:var(--text-light);margin-bottom:28px;">You do not have permission to view this page. This area is restricted to platform administrators.</p>
          <div style="display:flex;gap:12px;justify-content:center;">
            <a href="/dashboard" class="btn btn-primary">← Return to Dashboard</a>
            <a href="/" class="btn btn-ghost">Go Home</a>
          </div>
        </div>
      </div>
      ${renderFooter()}
    `));
  }

  const totalUsersStmt = db.prepare('SELECT COUNT(*) as count FROM users');
  totalUsersStmt.step();
  const totalUsers = totalUsersStmt.getAsObject().count;
  totalUsersStmt.free();

  const totalBookingsStmt = db.prepare('SELECT COUNT(*) as count FROM bookings');
  totalBookingsStmt.step();
  const totalBookings = totalBookingsStmt.getAsObject().count;
  totalBookingsStmt.free();

  const revenueStmt = db.prepare("SELECT COALESCE(SUM(total_price),0) as revenue FROM bookings WHERE status != 'cancelled'");
  revenueStmt.step();
  const revenue = revenueStmt.getAsObject().revenue;
  revenueStmt.free();

  const totalFlightsStmt = db.prepare('SELECT COUNT(*) as count FROM flights');
  totalFlightsStmt.step();
  const totalFlights = totalFlightsStmt.getAsObject().count;
  totalFlightsStmt.free();

  const totalHotelsStmt = db.prepare('SELECT COUNT(*) as count FROM hotels');
  totalHotelsStmt.step();
  const totalHotels = totalHotelsStmt.getAsObject().count;
  totalHotelsStmt.free();

  const confirmedStmt = db.prepare("SELECT COUNT(*) as count FROM bookings WHERE status = 'confirmed'");
  confirmedStmt.step();
  const confirmedBookings = confirmedStmt.getAsObject().count;
  confirmedStmt.free();

  const allUsersStmt = db.prepare('SELECT id, username, name, role, loyalty_points, created_at FROM users ORDER BY id');
  const allUsers = [];
  while (allUsersStmt.step()) {
    allUsers.push(allUsersStmt.getAsObject());
  }
  allUsersStmt.free();

  const userRows = allUsers.map(u => {
    const rbc = u.role === 'admin' ? 'role-badge-admin' : 'role-badge-user';
    return `
    <tr>
      <td style="font-weight:600;color:var(--text-mid);">#${u.id}</td>
      <td style="font-weight:600;">${esc(u.name)}</td>
      <td style="font-family:'Courier New',monospace;font-size:0.82rem;color:var(--text-mid);">${esc(u.username)}</td>
      <td><span class="role-badge ${rbc}">${esc(u.role)}</span></td>
      <td style="font-weight:500;">${Number(u.loyalty_points).toLocaleString()} pts</td>
      <td style="color:var(--text-light);">${esc(u.created_at).split('T')[0]}</td>
    </tr>`;
  }).join('');

  const allBookingsStmt = db.prepare(`SELECT b.*, u.name as user_name, f.flight_number, h.name as hotel_name
    FROM bookings b
    LEFT JOIN users u ON b.user_id = u.id
    LEFT JOIN flights f ON b.flight_id = f.id
    LEFT JOIN hotels h ON b.hotel_id = h.id
    ORDER BY b.created_at DESC`);
  const allBookings = [];
  while (allBookingsStmt.step()) {
    allBookings.push(allBookingsStmt.getAsObject());
  }
  allBookingsStmt.free();

  const auditRows = allBookings.map(b => `
    <tr>
      <td><span style="font-family:'Courier New',monospace;font-weight:700;color:var(--primary);">${esc(b.confirmation_code)}</span></td>
      <td style="font-weight:500;">${esc(b.user_name)}</td>
      <td>${b.flight_number ? esc(b.flight_number) : '<span style="color:var(--text-light);">—</span>'}</td>
      <td>${b.hotel_name ? esc(b.hotel_name) : '<span style="color:var(--text-light);">—</span>'}</td>
      <td><span class="status-badge status-${b.status}">${esc(b.status)}</span></td>
      <td style="font-weight:600;">$${Number(b.total_price).toFixed(2)}</td>
      <td style="color:var(--text-light);">${esc(b.created_at).split('T')[0]}</td>
    </tr>
  `).join('');

  res.send(pageShell('Admin Panel', user, `
    <div class="container">
      <div class="breadcrumb">
        <a href="/">Home</a> <span class="sep">/</span> <a href="/dashboard">Dashboard</a> <span class="sep">/</span> <span>Admin Panel</span>
