      <p class="page-subtitle">System administration, user management, and platform analytics</p>

      <div class="stats-grid" style="grid-template-columns: repeat(6, 1fr);">
        <div class="stat-card">
          <div class="stat-value blue">${totalUsers}</div>
          <div class="stat-label">Total Users</div>
        </div>
        <div class="stat-card">
          <div class="stat-value accent">${totalBookings}</div>
          <div class="stat-label">Total Bookings</div>
        </div>
        <div class="stat-card">
          <div class="stat-value teal">$${Number(revenue).toLocaleString(undefined, {minimumFractionDigits:0, maximumFractionDigits:0})}</div>
          <div class="stat-label">Revenue</div>
        </div>
        <div class="stat-card">
          <div class="stat-value amber">${totalFlights}</div>
          <div class="stat-label">Active Flights</div>
        </div>
        <div class="stat-card" style="position:relative;">
