      <div class="card" style="padding:24px;margin-bottom:24px;">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
          <h3 style="font-size:1.05rem;font-weight:700;">👥 User Management</h3>
          <span style="font-size:0.78rem;color:var(--text-light);background:var(--bg-light);padding:4px 12px;border-radius:20px;font-weight:500;">${totalUsers} users</span>
        </div>
        <div class="data-table-wrapper">
