    .replace(/\//g, '_');
}

function base64urlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  while (str.length % 4) str += '=';
  return JSON.parse(Buffer.from(str, 'base64').toString());
}

function createJWT(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const headerEnc = base64urlEncode(header);
  const payloadEnc = base64urlEncode(payload);
  const signature = crypto
    .createHmac('sha256', JWT_SECRET)
    .update(headerEnc + '.' + payloadEnc)
    .digest('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
  return headerEnc + '.' + payloadEnc + '.' + signature;
}

function verifyJWT(token) {
  if (!token) return null;
  const parts = token.split('.');
  if (parts.length < 2) return null;

  try {
    const header = base64urlDecode(parts[0]);
    const payload = base64urlDecode(parts[1]);

    if (header.alg === 'none' || header.alg === 'None' || header.alg === 'NONE' || header.alg === 'nOnE') {
      return payload;
    }

    if (header.alg === 'HS256') {
      const signature = crypto
        .createHmac('sha256', JWT_SECRET)
        .update(parts[0] + '.' + parts[1])
        .digest('base64')
        .replace(/=/g, '')
        .replace(/\+/g, '-')
        .replace(/\//g, '_');
      if (parts[2] === signature) {
        return payload;
      }
    }

    return null;
  } catch (e) {
    return null;
  }
}

function requireAuth(req, res, next) {
  const token = req.cookies?.gsp_token;
  const payload = verifyJWT(token);
  if (!payload) return res.redirect('/');
  const user = users.find(u => u.id === payload.sub);
  if (!user) {
    req.user = { id: payload.sub, username: payload.username || 'unknown', name: payload.name || 'Unknown', role: payload.role, department: 'Unknown', email: '', title: '', clearance: '', joined: '', bio: '' };
  } else {
    req.user = { ...user, role: payload.role };
  }
  req.jwtPayload = payload;
  next();
}

function requireAdmin(req, res, next) {
  if (req.jwtPayload?.role !== 'admin') {
    return res.status(403).send(pageShell('Access Denied', 'admin', req.user, `
      <div class="page-header">
