function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function statusBadge(status) {
  const map = {
    'Approved': 'badge-approved', 'Under Review': 'badge-review', 'Pending Hearing': 'badge-pending',
    'Draft': 'badge-draft', 'Paid': 'badge-paid', 'Overdue': 'badge-overdue', 'Pending': 'badge-pending',
    'Issued': 'badge-issued', 'Processing': 'badge-processing', 'Pending Review': 'badge-pending'
  };
  return `<span class="badge ${map[status] || 'badge-draft'}">${esc(status)}</span>`;
}

function initials(name) {
  return name.split(' ').filter(n => n.length > 0).map(n => n[0]).join('').substring(0, 2);
}

