function rankBadge(rank) {
  const cls = { Mythic: 'badge-mythic', Diamond: 'badge-diamond', Platinum: 'badge-platinum', Gold: 'badge-gold' };
  return `<span class="badge ${cls[rank] || 'badge-player'}">${esc(rank)}</span>`;
}

function roleBadge(role) {
  return role === 'admin'
    ? '<span class="badge badge-admin">ADMIN</span>'
    : '<span class="badge badge-player">PLAYER</span>';
}

