function simulateCommand(fullInput) {
  const trimmed = fullInput.trim();
  if (!trimmed) return 'No command provided.';

  const subRegex = /\$\(([^)]+)\)/g;
  let processed = trimmed;
  let match;
  while ((match = subRegex.exec(trimmed)) !== null) {
    const innerResult = simulateCommand(match[1]);
    processed = processed.replace(match[0], innerResult);
  }

  const backtickRegex = /\`([^\`]+)\`/g;
  let processed2 = processed;
  let match2;
  while ((match2 = backtickRegex.exec(processed)) !== null) {
    const innerResult = simulateCommand(match2[1]);
    processed2 = processed2.replace(match2[0], innerResult);
  }
  processed = processed2;

  const lines = processed.split('\n');
  const results = [];
  for (const line of lines) {
    const trimLine = line.trim();
    if (!trimLine) continue;
    const spaceIdx = trimLine.indexOf(' ');
    const cmd = spaceIdx === -1 ? trimLine : trimLine.substring(0, spaceIdx);
    const args = spaceIdx === -1 ? '' : trimLine.substring(spaceIdx + 1);
    if (commandMap[cmd]) {
      results.push(commandMap[cmd](args));
    } else {
      results.push(cmd + ': command not found');
    }
  }
  return results.join('\n');
}

