app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = dbGet('SELECT * FROM users WHERE username = ? AND password = ?', [username, password]);
  if (!user) {
    return res.send(renderLoginPage('Invalid username or password. Please try again.', ''));
  }
  const token = createSession(user.id);
  res.cookie('nx_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nx_session;
  if (token) delete sessions[token];
  res.clearCookie('nx_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const txRows = dbAll(
    'SELECT * FROM transactions WHERE account_number = ? ORDER BY date DESC LIMIT 5',
