function base64url(obj) {
  return Buffer.from(JSON.stringify(obj)).toString('base64url');
}

function signJwt(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const h = base64url(header);
  const p = base64url(payload);
  const sig = crypto.createHmac('sha256', JWT_SECRET).update(h + '.' + p).digest('base64url');
  return h + '.' + p + '.' + sig;
}

function verifyJwt(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const sig = crypto.createHmac('sha256', JWT_SECRET).update(parts[0] + '.' + parts[1]).digest('base64url');
    if (sig !== parts[2]) return null;
    return JSON.parse(Buffer.from(parts[1], 'base64url').toString());
  } catch { return null; }
}

function getUser(req) {
  const token = req.cookies?.nb_session;
  if (!token) return null;
  const payload = verifyJwt(token);
  if (!payload) return null;
  const row = db.exec("SELECT id, username, name, role, tier, email FROM users WHERE id = " + parseInt(payload.uid))[0];
  if (!row || !row.values[0]) return null;
  const u = row.values[0];
  return { id: u[0], username: u[1], name: u[2], role: payload.role || u[3], tier: u[4], email: u[5], jwtRole: payload.role };
}

function requireAuth(req, res, next) {
  const user = getUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireRole(role) {
  return (req, res, next) => {
    if (!req.user || req.user.jwtRole !== role) {
      return res.status(403).send(errorPage('Access Denied', 'You do not have the required role: ' + role));
    }
    next();
  };
}

function internalOnly(req, res, next) {
  const ip = req.ip || req.connection?.remoteAddress || '';
  const forwarded = req.headers['x-forwarded-for'] || '';
  if (ip === '127.0.0.1' || ip === '::1' || ip === '::ffff:127.0.0.1') {
    return next();
  }
  return res.status(403).json({ error: 'ACCESS DENIED', message: 'Internal API — direct access prohibited.' });
}

function sqlWaf(req, res, next) {
  const val = req.query.q || req.query.search || req.query.term || '';
  const blocked = ['UNION', 'SELECT', 'INSERT', 'DROP', 'DELETE', 'UPDATE', 'ALTER', 'CREATE'];
  for (const kw of blocked) {
    if (val.includes(kw)) {
      return res.status(400).json({ error: 'WAF_BLOCKED', message: 'Potentially dangerous SQL keyword detected: ' + kw });
    }
  }
  next();
}

function stripScripts(input) {
  return input.replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gi, '');
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

