  .sidebar-brand h1{font-family:var(--font-mono);font-size:16px;font-weight:700;letter-spacing:-0.5px}
  .sidebar-brand h1 span{color:var(--accent)}
  .sidebar-nav{flex:1;padding:12px 8px;display:flex;flex-direction:column;gap:2px}
  .sidebar-nav .section-label{font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:1.2px;color:var(--text-muted);padding:16px 12px 6px}
  .sidebar-nav a{display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:var(--radius);color:var(--text-secondary);font-size:13px;font-weight:500;transition:all 0.2s;text-decoration:none}
  .sidebar-nav a:hover{background:var(--accent-dim);color:var(--text-primary)}
  .sidebar-nav a.active{background:var(--accent-mid);color:var(--accent);box-shadow:inset 3px 0 0 var(--accent)}
  .sidebar-nav a .icon{font-size:16px;width:20px;text-align:center}
  .sidebar-user{padding:14px 12px;border-top:1px solid var(--border);display:flex;align-items:center;gap:10px}
  .sidebar-user .avatar{width:32px;height:32px;background:linear-gradient(135deg,var(--accent),var(--accent-purple));border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;flex-shrink:0}
  .sidebar-user .user-info{flex:1;min-width:0}
  .sidebar-user .user-name{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
  .sidebar-user .user-role{font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px}
  .main-content{margin-left:260px;flex:1;padding:32px;min-height:100vh}
