app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const rows = db.exec("SELECT id, username, name, role, tier FROM users WHERE username = ? AND password = ?", [username, password]);
  if (!rows[0] || !rows[0].values[0]) {
    return res.send(loginPageHtml('<div class="error-msg">Invalid credentials.</div>'));
  }
  const u = rows[0].values[0];
  const token = signJwt({ uid: u[0], role: u[3], tier: u[4] });
  res.cookie('nb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageHtml('', '<div class="error-msg">All fields required.</div>'));
  }
  const existing = db.exec("SELECT id FROM users WHERE username = ?", [username]);
  if (existing[0] && existing[0].values.length > 0) {
    return res.send(loginPageHtml('', '<div class="error-msg">Username taken.</div>'));
  }
  const refCode = 'USER-REF-' + String(Math.random()).slice(2, 8);
  db.run("INSERT INTO users (username, password, name, role, tier, email, balance, referral_code, referral_points, joined) VALUES (?,?,?,?,?,?,?,?,?,?)",
    [username, password, name, 'user', 'standard', username + '@email.com', 5000.00, refCode, 0, new Date().toISOString().split('T')[0]]);
  const newId = db.exec("SELECT last_insert_rowid()")[0].values[0][0];
  db.run("INSERT INTO accounts (user_id, account_number, account_type, balance, currency) VALUES (?,?,?,?,?)",
    [newId, 'NB-2025-' + String(newId).padStart(5, '0'), 'Checking', 5000.00, 'USD']);
  const token = signJwt({ uid: newId, role: 'user', tier: 'standard' });
  res.cookie('nb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('nb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const txRows = db.exec("SELECT description, amount, date, type FROM transactions WHERE user_id = ? ORDER BY date DESC LIMIT 5", [user.id]);
  const txns = txRows[0] ? txRows[0].values : [];
  const acctRows = db.exec("SELECT account_number, account_type, balance, currency FROM accounts WHERE user_id = ?", [user.id]);
  const accts = acctRows[0] ? acctRows[0].values : [];

  const txHtml = txns.map(t => `<tr>
    <td>${esc(t[0])}</td>
    <td style="color:${t[1] >= 0 ? 'var(--accent-green)' : 'var(--accent-red)'};font-family:var(--font-mono);">
      ${t[1] >= 0 ? '+' : ''}$${Number(t[1]).toFixed(2)}
    </td>
    <td>${esc(t[2])}</td>
    <td><span class="badge ${t[3] === 'credit' ? 'badge-credit' : 'badge-debit'}">${esc(t[3])}</span></td>
  </tr>`).join('');

  const totalBalance = accts.reduce((s, a) => s + a[2], 0);

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.name.split(' ')[0])}</h1>
      <p class="subtitle">NexusBank Online Banking Dashboard</p>
    </div>
    ${user.tier === 'premium' ? '<div class="premium-banner"><span class="icon">⭐</span><span class="text">Premium account — Access to exclusive research notes and priority support</span></div>' : ''}
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">$${totalBalance.toFixed(2)}</div><div class="stat-label">Total Balance</div></div>
      <div class="stat-card"><div class="stat-value">${accts.length}</div><div class="stat-label">Accounts</div></div>
      <div class="stat-card"><div class="stat-value">${txns.length}</div><div class="stat-label">Recent Txns</div></div>
      <div class="stat-card"><div class="stat-value"><span class="badge ${user.tier === 'premium' ? 'badge-premium' : 'badge-standard'}">${esc(user.tier)}</span></div><div class="stat-label">Tier</div></div>
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Transactions</h3>
      <table class="data-table">
        <thead><tr><th>Description</th><th>Amount</th><th>Date</th><th>Type</th></tr></thead>
        <tbody>${txHtml || '<tr><td colspan="4" style="text-align:center;color:var(--text-muted);">No transactions yet</td></tr>'}</tbody>
      </table>
    </div>
  `));
});

