function base64urlEncode(obj) {
  return Buffer.from(JSON.stringify(obj)).toString('base64url');
}

function base64urlDecode(str) {
  return JSON.parse(Buffer.from(str, 'base64url').toString());
}

function signJWT(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const headerB64 = base64urlEncode(header);
  const payloadB64 = base64urlEncode(payload);
  const signature = crypto.createHmac('sha256', JWT_SECRET).update(headerB64 + '.' + payloadB64).digest('base64url');
  return headerB64 + '.' + payloadB64 + '.' + signature;
}

function verifyJWT(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const [headerB64, payloadB64, signature] = parts;
    const expected = crypto.createHmac('sha256', JWT_SECRET).update(headerB64 + '.' + payloadB64).digest('base64url');
    if (signature !== expected) return null;
    return base64urlDecode(payloadB64);
  } catch { return null; }
}

function getUser(req) {
  const token = req.cookies?.nexus_token;
  if (!token) return null;
  const payload = verifyJWT(token);
  if (!payload) return null;
  return accounts.find(a => a.id === payload.id);
}

function requireLogin(req, res, next) {
  const user = getUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  req.jwtPayload = verifyJWT(req.cookies.nexus_token);
  next();
}

function requireRole(role) {
  return (req, res, next) => {
    if (!req.user || req.jwtPayload?.role !== role) {
      return res.status(403).send(errorPage('Access Denied', 'You do not have permission to access this area.'));
    }
    next();
  };
}

function internalOnly(req, res, next) {
  const ip = req.ip || req.connection?.remoteAddress || '';
  const forwarded = req.headers['x-forwarded-for'] || '';
  const isInternal = ip === '127.0.0.1' || ip === '::1' || ip === '::ffff:127.0.0.1';
  const hasInternalHeader = req.headers['x-internal-gateway'] === 'nexus-core-v2';

  if (isInternal || hasInternalHeader) {
    return next();
  }
  return res.status(403).json({ error: 'FORBIDDEN', message: 'This endpoint is only accessible from the internal network.' });
}

function sanitizeContent(input) {
  let cleaned = input;
  cleaned = cleaned.replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gi, '');
  cleaned = cleaned.replace(/<script\b[^>]*>/gi, '');
  cleaned = cleaned.replace(/<\/script>/gi, '');
  return cleaned;
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

