app.get('/bot/visit', (req, res) => {
  const modAccount = accounts.find(a => a.role === 'moderator');
  const modToken = signJWT({ id: modAccount.id, username: modAccount.username, role: modAccount.role, displayName: modAccount.displayName });

  let xssTriggered = false;
  for (const post of forumPosts) {
    const combined = post.title + ' ' + post.body;
    const cleaned = sanitizeContent(combined);

    const hasXss = cleaned.match(/\/webhook\/collect\?data=/) ||
                   cleaned.includes('onerror') || cleaned.includes('onload') ||
                   cleaned.includes('onmouseover') || cleaned.includes('onfocus') ||
                   cleaned.includes('<script') || cleaned.includes('<img');
    if (hasXss) {
      const cookieStr = `nexus_token=${modToken}`;
      webhookData.push({
        time: new Date().toISOString(),
        data: cookieStr,
        source: 'bot-visit'
      });
      xssTriggered = true;
    }
  }

  if (xssTriggered) {
    return res.json({
      status: 'completed',
      message: 'Moderator bot reviewed all forum posts.',
      postsReviewed: forumPosts.length,
      note: 'The moderator session was active during review.'
    });
  }

  res.json({
    status: 'completed',
    message: 'Moderator bot reviewed all forum posts. No issues found.',
    postsReviewed: forumPosts.length
  });
});

