app.post('/admin/fetch', requireLogin, requireRole('admin'), async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'URL is required' });

  try {
    const parsedUrl = new URL(url);

    const response = await fetch(url, {
      headers: {
        'X-Internal-Gateway': 'nexus-core-v2',
        'Cookie': req.headers.cookie || ''
      },
      redirect: 'follow'
    });

    const contentType = response.headers.get('content-type') || '';
    let body;
    if (contentType.includes('application/json')) {
      body = await response.json();
    } else {
      body = await response.text();
    }

    res.json({ status: response.status, body });
  } catch (e) {
    res.json({ error: 'Failed to fetch: ' + e.message });
  }
});

