app.get('/internal/api/leaderboard', internalOnly, (req, res) => {
  const q = req.query.q || '';

  if (!q) {
    return res.json({ error: 'Query parameter q is required. Example: /internal/api/leaderboard?q=all' });
  }

  try {
    let query;
    if (q === 'all') {
      query = "SELECT id, display_name, level, class, guild, wins, losses, rank_points FROM players ORDER BY rank_points DESC";
    } else {
      query = "SELECT id, display_name, level, class, guild, wins, losses, rank_points FROM players WHERE display_name LIKE '%" + q + "%' OR class LIKE '%" + q + "%' OR guild LIKE '%" + q + "%' ORDER BY rank_points DESC";
    }

    const result = db.exec(query);
    const rows = [];
    if (result.length > 0) {
      const columns = result[0].columns;
      for (const row of result[0].values) {
        const obj = {};
        columns.forEach((col, i) => obj[col] = row[i]);
        rows.push(obj);
      }
    }

    res.json({ query: q, results: rows, count: rows.length });
  } catch (e) {
    res.json({ error: 'Query execution failed', details: e.message });
  }
});

