function base64UrlEncode(obj) {
  return Buffer.from(JSON.stringify(obj)).toString('base64url');
}

function base64UrlDecode(str) {
  return JSON.parse(Buffer.from(str, 'base64url').toString());
}

function signJwt(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const headerEnc = base64UrlEncode(header);
  const payloadEnc = base64UrlEncode(payload);
  const signature = crypto.createHmac('sha256', JWT_SECRET).update(headerEnc + '.' + payloadEnc).digest('base64url');
  return headerEnc + '.' + payloadEnc + '.' + signature;
}

function verifyJwt(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const [headerEnc, payloadEnc, signature] = parts;
    const expected = crypto.createHmac('sha256', JWT_SECRET).update(headerEnc + '.' + payloadEnc).digest('base64url');
    if (signature !== expected) return null;
    return base64UrlDecode(payloadEnc);
  } catch {
    return null;
  }
}

function getAuthUser(req) {
  const token = req.cookies?.sw_token;
  if (!token) return null;
  const payload = verifyJwt(token);
  if (!payload) return null;
  const user = users.find(u => u.id === payload.sub);
  if (!user) return null;
  return { ...user, role: payload.role, tier: payload.tier || user.tier };
}

function requireAuth(req, res, next) {
  const user = getAuthUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireStaff(req, res, next) {
  const user = getAuthUser(req);
  if (!user) return res.status(401).json({ error: 'Authentication required' });
  if (user.role !== 'staff' && user.role !== 'admin') {
    return res.status(403).json({ error: 'ACCESS DENIED', message: 'Staff or admin role required.' });
  }
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

