function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const isVip = user.tier === 'vip';
  const isStaff = user.role === 'staff' || user.role === 'admin';

  let navItems = `
    <div class="section-label">Travel</div>
    <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
      <span class="icon">🏠</span> Dashboard
    </a>
    <a href="/flights" class="${activePage === 'flights' ? 'active' : ''}">
      <span class="icon">✈️</span> Flights
    </a>
    <a href="/hotels" class="${activePage === 'hotels' ? 'active' : ''}">
      <span class="icon">🏨</span> Hotels
    </a>
    <a href="/bookings" class="${activePage === 'bookings' ? 'active' : ''}">
      <span class="icon">📋</span> My Bookings
    </a>
    <div class="section-label">Account</div>
    <a href="/loyalty" class="${activePage === 'loyalty' ? 'active' : ''}">
      <span class="icon">🎁</span> Loyalty & Promos
