app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.redirect('/?error=Invalid+credentials');
  }
  const token = signJwt({ sub: user.id, username: user.username, role: user.role, tier: user.tier, iat: Math.floor(Date.now() / 1000) });
  res.cookie('sw_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.redirect('/?error=All+fields+are+required');
  }
  if (users.find(u => u.username === username)) {
    return res.redirect('/?error=Username+already+taken');
  }
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    role: 'user',
    email: username + '@skyward.io',
    tier: 'basic',
    loyaltyPoints: 100,
    joined: new Date().toISOString().split('T')[0],
  };
  users.push(newUser);
  const token = signJwt({ sub: newUser.id, username: newUser.username, role: newUser.role, tier: newUser.tier, iat: Math.floor(Date.now() / 1000) });
  res.cookie('sw_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('sw_token');
  res.redirect('/');
});

