const userAppliedPromos = {};

app.post('/api/loyalty/apply-promo', requireAuth, (req, res) => {
  const user = req.user;
  const realUser = users.find(u => u.id === user.id);
  if (!realUser) return res.status(404).json({ error: 'User not found' });

  const { code } = req.body;

  if (!code || typeof code !== 'string') {
    return res.status(400).json({ error: 'Invalid promo code format' });
  }

  const upperCode = code.toUpperCase().trim();
  const promo = promoCodes[upperCode];
  if (!promo) {
    return res.status(400).json({ error: 'Invalid promo code: ' + upperCode });
  }

  if (!userAppliedPromos[realUser.id]) {
    userAppliedPromos[realUser.id] = [];
  }

  const applied = userAppliedPromos[realUser.id];
  const countThisCode = applied.filter(c => c === upperCode).length;

  if (countThisCode >= 1) {
    return res.status(400).json({ error: 'Promo code ' + upperCode + ' has already been applied to your account.' });
  }

  applied.push(upperCode);

  const pointsAwarded = promo.type === 'percent' ? promo.discount * 40 : promo.discount * 20;
  realUser.loyaltyPoints += pointsAwarded;

  let tierUpgrade = false;
  if (realUser.loyaltyPoints >= VIP_POINTS_THRESHOLD && realUser.tier !== 'vip') {
    realUser.tier = 'vip';
    tierUpgrade = true;

    const newToken = signJwt({ sub: realUser.id, username: realUser.username, role: realUser.role, tier: 'vip', iat: Math.floor(Date.now() / 1000) });
    res.cookie('sw_token', newToken, { httpOnly: false, sameSite: 'lax' });
  }

  return res.json({
    success: true,
    message: `Code ${upperCode} applied! +${pointsAwarded} points. Total: ${realUser.loyaltyPoints.toLocaleString()}` + (tierUpgrade ? ' 🎉 You\'ve been upgraded to VIP!' : ''),
    points: realUser.loyaltyPoints,
    tierUpgrade: tierUpgrade,
  });
});

app.post('/api/loyalty/apply-promos', requireAuth, (req, res) => {
  const user = req.user;
  const realUser = users.find(u => u.id === user.id);
  if (!realUser) return res.status(404).json({ error: 'User not found' });

  let { codes } = req.body;

  if (!codes || !Array.isArray(codes)) {
    return res.status(400).json({ error: 'Expected an array of promo codes in "codes" field' });
  }

  if (!userAppliedPromos[realUser.id]) {
    userAppliedPromos[realUser.id] = [];
  }

  const results = [];
  let totalPointsAwarded = 0;

  for (const rawCode of codes) {
    if (typeof rawCode !== 'string') continue;
    const upperCode = rawCode.toUpperCase().trim();
    const promo = promoCodes[upperCode];

    if (!promo) {
      results.push({ code: upperCode, success: false, reason: 'Invalid code' });
      continue;
    }

    const applied = userAppliedPromos[realUser.id];
    const alreadyInSession = results.filter(r => r.code === upperCode && r.success).length;

    if (applied.includes(upperCode) && alreadyInSession === 0) {
      results.push({ code: upperCode, success: false, reason: 'Already applied' });
      continue;
    }

    const pointsAwarded = promo.type === 'percent' ? promo.discount * 40 : promo.discount * 20;
    realUser.loyaltyPoints += pointsAwarded;
    totalPointsAwarded += pointsAwarded;
    results.push({ code: upperCode, success: true, pointsAwarded });
  }

  const newlyApplied = results.filter(r => r.success).map(r => r.code);
  for (const c of newlyApplied) {
    if (!userAppliedPromos[realUser.id].includes(c)) {
      userAppliedPromos[realUser.id].push(c);
    }
  }

  let tierUpgrade = false;
  if (realUser.loyaltyPoints >= VIP_POINTS_THRESHOLD && realUser.tier !== 'vip') {
    realUser.tier = 'vip';
    tierUpgrade = true;
    const newToken = signJwt({ sub: realUser.id, username: realUser.username, role: realUser.role, tier: 'vip', iat: Math.floor(Date.now() / 1000) });
    res.cookie('sw_token', newToken, { httpOnly: false, sameSite: 'lax' });
  }

  return res.json({
    success: true,
    results,
    totalPointsAwarded,
    currentPoints: realUser.loyaltyPoints,
    tierUpgrade,
    message: tierUpgrade ? '🎉 Congratulations! You\'ve been upgraded to VIP!' : `Applied ${newlyApplied.length} code(s). +${totalPointsAwarded} points.`
  });
});

