      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Booking Detail</h3>
      <div id="booking-detail-content"></div>
    </div>

    <script>
      async function viewBooking(id) {
        try {
          const resp = await fetch('/api/staff/bookings/' + encodeURIComponent(id));
          const data = await resp.json();
          const detailDiv = document.getElementById('booking-detail');
